INSERT INTO public.photos VALUES (23730, 'Estaciв”ңв”Ӯn Delicias 1963', 'Panorв”ңГӯmica que comienza en una vista parcial de la estaciв”ңв”Ӯn Delicias o de Caminreal, para mostrar luego el campo de fв”ңв•‘tbol de la Renfe, un dв”ңВЎa de partido. Fuente: www.facebook.com/photo.php?fbid=10207332728345162&set...', 1963, 1963, 1963, 'Anos 60', 'DELICIAS', 41.65713200, -0.90873600, '0101000020E6100000D65416855D14EDBFD993C0E61CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33746173495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33746173495.webp', 'https://www.flickr.com/photos/zaragozaantigua/33746173495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23732, 'Av. de Navarra 1980', 'Imagen centrada parcialmente en la gran explanada de acceso (que incluв”ңВЎa в”ңГӯrboles) a la original estaciв”ңв”Ӯn del ferrocarril Central de Aragв”ңв”Ӯn o Caminreal, luego Zaragoza-Delicias. Los andenes y vв”ңВЎas quedaban en las traseras del referencial edificio diseв”ңв–’ado por el arquitecto Luis Gutiв”ңВ®rrez Soto. Justo a la derecha, fuera de plano, se localizaba el Campo de Deportes Renfe "Delicias" para prв”ңГӯctica del balompiв”ңВ®. Fuente visual: AMZ.', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65713200, -0.90927300, '0101000020E61000008A58C4B0C318EDBFD993C0E61CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38492538825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38492538825.webp', 'https://www.flickr.com/photos/zaragozaantigua/38492538825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23734, 'Hostal y garaje Oroel c.1962', 'Imagen capturada desde cierta altura en la avenida de Navarra y centrada en el moderno hostal y garaje Oroel, ubicados en el nв”¬в•‘ 50 de la avenida, cuando los accesos, la acera y la calzada aв”ңв•‘n no habв”ңВЎan sido urbanizadas convenientemente. A la izquierda, vista parcial del moderno Mercado de Pescados. A la derecha, el vecino y tambiв”ңВ®n novв”ңВЎsimo inmueble edilicio del nв”¬в•‘ 40 de la avenida. Fuente visual: www.delcampe.net', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65546900, -0.90589000, '0101000020E610000005C078060DFDECBF5A457F68E6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45638708542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45638708542.webp', 'https://www.flickr.com/photos/zaragozaantigua/45638708542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23959, 'Cine Delicias 1974', 'Cine Delicias, construido en 1945 con proyecto de Teodoro Rв”ңВЎos Balaguer en la avenida de Madrid nв”¬в•‘ 147, en el solar del homв”ңв”Ӯnimo cine proyectado en 1923 por Francisco Albiв”ңв–’ana, que entre 1925 y 1944 fuera Cinema Espaв”ңв–’a. En la imagen, marquesina del cine, clausurado en 1973. A la izquierda, la Escuela Nacional Emilio Moreno Calvete, y a la derecha, la "Fв”ңГӯbrica de alambres y puntas de Parв”ңВЎs de Arribas Hermanos", esquinera con la calle de Sangenis.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65322600, -0.90489500, '0101000020E6100000A20BEA5BE6F4ECBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14907444173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14907444173.webp', 'https://www.flickr.com/photos/zaragozaantigua/14907444173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24029, 'Mercado de Pescados 1960', 'Quiso la causalidad que el 18 de julio de ese aв”ңв–’o fuera inaugurado el nuevo Mercado de Pescados de la ciudad, con diseв”ңв–’o del arquitecto municipal Marcelo Carquв”ңВ® Aniesa, y ubicado en la avenida de Navarra, antigua de Caminreal. La imagen captura un emotivo momento de la iniciв”ңГӯtica ceremonia, cuando el plenario de autoridades civiles y militares estв”ңГӯ a punto de recibir el confesional, y tradicionalista, hisopazo. En primera lв”ңВЎnea de impacto, Antonio Zubiri Vidal, presidente de la DPZ; Josв”ңВ® Manuel Pardo de Santayana, recio gobernador civil; Luis Gв”ңв”Ӯmez Laguna, alcalde; y Josв”ңВ® Lacalle Larraga, jefe de la regiв”ңв”Ӯn aв”ңВ®rea pirenaica. Mв”ңГӯs resguardados, Juan Cabrera Felipe, rector de la Universidad; Gumersindo Claramunt Pastor, presidente del Banco Zaragozano, y algв”ңв•‘n teniente de alcalde que otro, como Luis Ariв”ңв–’o Malo. Las gafas de sol eran ese dв”ңВЎa una necesidad, no una falta de respeto, por supuesto. Unos aв”ңв–’os despuв”ңВ®s, los exteriores de este moderno mercado aparecerв”ңВЎan en la pelв”ңВЎcula "Culpable para un delito", como escenario del nocturno deambular por un ficticio y portuario barrio chino. El mercado estuvo activo, como tal, hasta los aв”ңв–’os 80, en que fue convertido en Centro Cв”ңВЎvico del barrio de las Delicias. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal de Zaragoza.', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65555100, -0.90662900, '0101000020E6100000AB5D13D21A03EDBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25351324512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25351324512.webp', 'https://www.flickr.com/photos/zaragozaantigua/25351324512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24793, 'Reloj de sol 2009', 'Foto: Josв”ңВ® Elв”ңВЎas. Trabajos de instalaciв”ңв”Ӯn en Vadorrey del gnomon del mayor reloj solar del mundo, junto al parque de Oriente, el 30 de octubre de 2009. Se trata de una estructura de acero inoxidable de 46 metros, diseв”ңв–’ada por Juan Antonio Ros. El proyecto incluв”ңВЎa el acondicionamiento del entorno, con fuentes, jardines y otras estructuras asociadas. En 2011 se colocв”ңв”Ӯ la segmentaciв”ңв”Ӯn horaria en el pavimento y en 2015 se aв”ңв–’adiв”ңв”Ӯ una esfera metв”ңГӯlica interpretativa. En 2017 se sigue a la espera de que la obra se complete, configurando la llamada plaza del Tiempo. En la imagen, al fondo, el barrio de la Jota, tras la calle del Marquв”ңВ®s de la Cadena. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2009, 2009, 2009, 'Siglo XXI', 'LAS FUENTES', 41.65420100, -0.86046500, '0101000020E6100000D4484BE5ED88EBBF5801BEDBBCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32441676234.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32441676234.webp', 'https://www.flickr.com/photos/zaragozaantigua/32441676234/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24034, 'Calle de Aragв”ңв”Ӯn c.1942', 'Imagen capturada ante el antiguo nв”¬в•‘ 1 de la calle de Aragв”ңв”Ӯn, que desde 1937 habв”ңВЎa sido habilitado como provisional iglesia parroquial del barrio de las Delicias, dada la paralizaciв”ңв”Ӯn de las obras de la iglesia de San Valero en la calle de Unceta. Las instalaciones de la imagen, casi esquineras con la avenida de Madrid (hacia la izquierda, fuera de plano), contaban con dependencias parroquiales en espacial cohabitaciв”ңв”Ӯn con el grupo de la Juventud Catв”ңв”Ӯlica Obrera del barrio, creado en 1934. Esta situaciв”ңв”Ӯn se prolongв”ңв”Ӯ hasta que a principios del aв”ңв–’o 1947 fue inaugurada formalmente la nueva iglesia parroquial de San Valero, y unos aв”ңв–’os antes, esta calle de Aragв”ңв”Ӯn habв”ңВЎa sido ya redenominada de Don Alonso de Aragв”ңв”Ӯn. Ninguno de los inmuebles de la imagen perdura. Fuente visual: La Crв”ңв”Ӯnica de Zaragoza: Delicias-La Almozara.', 1942, 1942, 1942, 'Anos 40', 'DELICIAS', 41.65400600, -0.90330200, '0101000020E6100000202A8D98D9E7ECBFA3B1F677B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27230000798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27230000798.webp', 'https://www.flickr.com/photos/zaragozaantigua/27230000798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24169, 'Estaciв”ңв”Ӯn de Caminreal 1933', 'El 2 de abril de 1933 se inaugurв”ңв”Ӯ el tramo ferroviario conocido como "El Caminreal" comunicando Teruel y Valencia con Zaragoza y enlazando a su vez con la lв”ңВЎnea internacional de Canfranc, reciв”ңВ®n inaugurada en 1928. El diseв”ңв–’o y la ejecuciв”ңв”Ӯn de la estaciв”ңв”Ӯn de Ferrocarril Zaragoza-Delicias fue llevada a cabo por el arquitecto Luis Gutiв”ңВ®rrez Soto, siendo inaugurada en 1932. La estaciв”ңв”Ӯn de ferrocarril Zaragoza-Delicias constituye el ejemplo mв”ңГӯs importante de las diversas estaciones construidas en la lв”ңВЎnea Zaragoza-Caminreal. Fuente visual: Archivo Asociaciв”ңв”Ӯn Amigos del Ferrocarril.', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65753900, -0.90946100, '0101000020E61000003D997FF44D1AEDBF1A6CEA3C2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781164919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781164919.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781164919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24192, 'Estaciв”ңв”Ӯn Caminreal 1933', 'Imagen de la celebrada llegada, desde Valencia, de los primeros viajeros de la lв”ңВЎnea de ferrocarril Caminreal-Zaragoza, en la primavera de 1933. Al fondo, la nueva Estaciв”ңв”Ӯn terminal de lв”ңВЎnea, entre Almozara y Delicias. Delante de ella, la gran &quot;explanada de la Estaciв”ңв”Ӯn&quot;, y la &quot;Entrada&quot; a la misma desde la carretera de Logroв”ңв–’o a Zaragoza. La engalanada y festiva comitiva se dirige hacia la ciudad, que queda a la derecha. En las carrozas, las &quot;seв”ңв–’oritas Miss Valencia, Miss Aragв”ңв”Ӯn, Miss Huesca, la Fallera Mayor de Valencia, y la Matrona de la Repв”ңв•‘blica&quot; camino de la Diputaciв”ңв”Ӯn Provincial, a un sentido acto de confraternizaciв”ңв”Ӯn entre el pueblo valenciano y el aragonв”ңВ®s. Fuente visual: Fot. Aldea, &quot;Mundo Grв”ңГӯfico&quot; (Madrid).', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65671300, -0.90989100, '0101000020E61000007097FDBAD31DEDBFD5EDEC2B0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21725304758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21725304758.webp', 'https://www.flickr.com/photos/zaragozaantigua/21725304758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24193, 'Estaciв”ңв”Ӯn Delicias 1934', 'En abril de 1933 se inaugurв”ңв”Ӯ el tramo ferroviario conocido como "El Caminreal" comunicando Teruel y Valencia con Zaragoza, y enlazando a su vez por el norte con la lв”ңВЎnea internacional de Canfranc, inaugurada en 1928. En la imagen, la estaciв”ңв”Ӯn terminal del "Ferrocarril Central de Aragв”ңв”Ӯn", nombre comercial de la Compaв”ңв–’в”ңВЎa que gestionaba la lв”ңВЎnea, capturada desde la enorme explanada por la que se accedв”ңВЎa a ella desde la carretera de Logroв”ңв–’o.', 1934, 1934, 1934, 'Anos 30', 'DELICIAS', 41.65753900, -0.90946100, '0101000020E61000003D997FF44D1AEDBF1A6CEA3C2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21905448916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21905448916.webp', 'https://www.flickr.com/photos/zaragozaantigua/21905448916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24856, 'Avenida de Madrid 1973', 'Imagen de la avenida de Madrid, a la altura de la calle Ramв”ңв”Ӯn de Campoamor (izquierda) y Delicias (derecha), en las inmediaciones de la plaza de Huesca, capturada cuando un grupo de operarios procede al levantamiento de las vв”ңВЎas del tranvв”ңВЎa tendidas en la avenida, sin trв”ңГӯnsito desde su erradicaciв”ңв”Ӯn de servicios previa. En 1969 ya fue suprimida la lв”ңВЎnea 14, Oliver, y a finales de 1971, en cumplimiento de la "terminator" hoja de ruta prevista, le tocв”ңв”Ӯ a la lв”ңВЎnea 5, Venecia-Delicias. La prevista sustituciв”ңв”Ӯn por autobuses urbanos con motor de explosiв”ңв”Ӯn (que en algв”ңв•‘n caso ya comenzв”ңв”Ӯ en "vida activa" de algunas lв”ңВЎneas de tranvв”ңВЎa) queda reflejado en la imagen con una unidad de la lв”ңВЎnea 21, Plaza del Pilar-Oliver, en direcciв”ңв”Ӯn a Oliver. Por su parte, la lв”ңВЎnea 5 del tranvв”ңВЎa fue sustituida por la lв”ңВЎnea 31 de bus, Venecia-Delicias, y la 32, Cuв”ңВ®llar-Delicias, sin aportar novedades en el trazado de la ruta. Grandes e indudables avances de la movilidad moderna, "ad maiorem vehiculi gloriam". Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65312400, -0.90608100, '0101000020E6100000FDDCD0949DFEECBFC91D369199D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31392485172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31392485172.webp', 'https://www.flickr.com/photos/zaragozaantigua/31392485172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24858, 'Pl. de Huesca 1974', 'Foto: Pilar Borobio. Vista de la plaza de Huesca, con la avenida de Madrid a la espalda y la calle de Leonardo Torres Quevedo al fondo. Un autobв”ңв•‘s urbano de la lв”ңВЎnea 24 recoge a los pasajeros. Fuente: Heraldo de Aragв”ңв”Ӯn.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65319100, -0.90662000, '0101000020E6100000DEC83CF20703EDBF51853FC39BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32042343840.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32042343840.webp', 'https://www.flickr.com/photos/zaragozaantigua/32042343840/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25932, 'Calle de Ramв”ңв”Ӯn Campoamor 1955', 'Imagen capturada desde la avenida de Madrid y centrada en el desemboque desde la calle de Ramв”ңв”Ӯn Campoamor de la composiciв”ңв”Ӯn 112+102 (motor+remolque) en servicio en la tranviaria lв”ңВЎnea 5 "Venecia-Delicias". Aquв”ңВЎ se encontraba la terminal en el barrio de Delicias de esta lв”ңВЎnea, en el entorno de la plaza de Rocasolano. Esta unidad motora de la serie de los "100" estuvo en servicio hasta la clausura de la lв”ңВЎnea en 1971, siendo transferida luego a la lв”ңВЎnea 1 "Bajo Aragв”ңв”Ӯn", y desguazada en 1975 cuando esta fue tambiв”ңВ®n clausurada. Como telв”ңв”Ӯn edilicio, y de izquierda a derecha, los antiguos inmuebles del nв”¬в•‘ 84 de la avenida de Madrid y los nв”ңв•‘meros 26, 24 y 22 de la calle de Ramв”ңв”Ӯn Campoamor, todos ellos desaparecidos. A la derecha, mв”ңВЎnima visual del esquinero nв”¬в•‘ 82 de la avenida de Madrid, que perdura como afortunada excepciв”ңв”Ӯn a la norma. Fuente visual: foto Jordi Ibв”ңГӯв”ңв–’ez, en Los tranvв”ңВЎas de Zaragoza, Javier Peв”ңв–’a Gonzalvo, Josв”ңВ® Marв”ңВЎa Valero Suв”ңГӯrez, Zaragoza: DPZ, 1985.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65297600, -0.90697300, '0101000020E61000003A5CAB3DEC05EDBF5589B2B794D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41455524114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41455524114.webp', 'https://www.flickr.com/photos/zaragozaantigua/41455524114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26004, 'La Bombarda 1991', 'Foto: Archivo Taumar (Irene Taulв”ңВ®s y Rafael Margalв”ңВ®). Vista aв”ңВ®rea parcial del barrio de La Bombarda, con solares aв”ңв•‘n sin edificar en primer tв”ңВ®rmino, y la confluencia de la calle Ramiro I de Aragв”ңв”Ӯn con la avenida de Navarra (arriba a la izquierda). Arriba a la derecha, el barrio de Monsalud, tras el IES Fв”ңВ®lix de Azara. Fuente: www.facebook.com/photo.php?fbid=1687671944789838&set=...', 1991, 1991, 1991, 'Anos 90', 'DELICIAS', 41.65701600, -0.91586800, '0101000020E6100000637E6E68CA4EEDBF7079AC1919D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22220301008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22220301008.webp', 'https://www.flickr.com/photos/zaragozaantigua/22220301008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26006, 'La Bombarda 1994', 'Foto: Archivo Taumar (Irene Taulв”ңВ®s y Rafael Margalв”ңВ®). Vista aв”ңВ®rea del barrio de La Bombarda, entre la avenida de Navarra (arriba) y la Vв”ңВЎa Hispanidad (abajo). Fuente: www.facebook.com/photo.php?fbid=1687674321456267&set=...', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65816300, -0.91965500, '0101000020E6100000CB4A9352D06DEDBFF83768AF3ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22220881998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22220881998.webp', 'https://www.flickr.com/photos/zaragozaantigua/22220881998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26007, 'Calle de Juliв”ңГӯn Sanz Ibв”ңГӯв”ңв–’ez 1994', 'Foto: Archivo Taumar (Irene Taulв”ңВ®s y Rafael Margalв”ңВ®). Vista aв”ңВ®rea del entorno de la calle de Juliв”ңГӯn Sanz Ibв”ңГӯв”ңв–’ez, que atraviesa la imagen de arriba abajo. A su derecha, la avenida de Madrid. Fuente: www.facebook.com/photo.php?fbid=1687671941456505&set=...', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65177800, -0.91659000, '0101000020E610000086E63A8DB454EDBF4B2025766DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22221560139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22221560139.webp', 'https://www.flickr.com/photos/zaragozaantigua/22221560139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22617, 'Calle de Galв”ңГӯn Bergua 1976', 'Urbanizaciв”ңв”Ӯn de Las Delicias entre Los Enlaces y el Hospital Psiquiв”ңГӯtrico. Centra la imagen el polв”ңВ®mico bloque de Construcciones Cinca S.A., levantado sin licencia de obra y contraviniendo ordenanzas municipales, luego legalizado a la carta. Al fondo, bloque sobre solar de la fв”ңГӯbrica de Criado y Lorenzo. Tras в”ңВ®l, la avenida de Madrid, y a su izquierda, esqueleto del bloque en construcciв”ңв”Ӯn junto a Los Enlaces. En primer tв”ңВ®rmino, temporal paisaje lunar.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64832000, -0.91562000, '0101000020E61000005B087250C24CEDBFDEAB5626FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19310103081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19310103081.webp', 'https://www.flickr.com/photos/zaragozaantigua/19310103081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22747, 'Calle del Escultor Palao 1976', 'Imagen de la calle Escultor Palao en el "Polв”ңВЎgono 22", cuando era un sorprendente vial a tiempo parcial, pues parece ser que la empresa constructora "Criado y Lorenzo, SA" cerraba los portones al final de cada jornada, y los peatones y caminantes debв”ңВЎan buscar entonces otra ruta. Cosas de la Zaragoza de la в”ңВ®poca. Lo mismo sucedв”ңВЎa en las inmediatas Roger de Flor, y Galв”ңГӯn Bergua. Tras la valla abierta con el sв”ңВЎmbolo "prohibido el paso", la calle Galв”ңГӯn Bergua. Al fondo, antiguos bloques inmediatos a la desaparecida fв”ңГӯbrica de Criado y Lorenzo, luego derribados y sustituidos por otros mв”ңГӯs nuevos. Detrв”ңГӯs de ellos, a la derecha, emerge en obras el moderno bloque del nв”¬в•‘ 96 de la Vв”ңВЎa Hispanidad. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64859500, -0.91534000, '0101000020E61000007C0F971C774AEDBFB0AC342905D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32402673544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32402673544.webp', 'https://www.flickr.com/photos/zaragozaantigua/32402673544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22769, 'Calle de Ramв”ңв”Ӯn Salanova 1976', 'Imagen capturada desde la montaraz y agreste zona donde se trazarв”ңВЎa luego la prolongaciв”ңв”Ӯn de Duquesa Villahermosa, con interesante visual del estado de las cosas en la zona suroeste del "Manicomio". A la izquierda, vista parcial de dos de los trillizos bloques de la novв”ңВЎsima calle de Ramв”ңв”Ӯn Salanova. En el centro de la imagen, descampados varios para trв”ңГӯnsito peatonal, y aparcamiento, que se extienden hasta el muro perimetral del enorme espacio verde del Hospital Psiquiв”ңГӯtrico de Nuestra Seв”ңв–’ora del Pilar, del que emergen algunos de sus pabellones. Al fondo, estructuras de los nuevos bloques en construcciв”ңв”Ӯn entre la calle de Barcelona, y la de Daroca. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64558000, -0.91245400, '0101000020E61000001D5723BBD232EDBFD1798D5DA2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33445685111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33445685111.webp', 'https://www.flickr.com/photos/zaragozaantigua/33445685111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22946, 'N.в”¬В¬ S.в”¬В¬ del Salz 1981', 'Campo del Club de Fв”ңв•‘tbol Atlв”ңВ®tico Delicias, denominado de Nuestra Seв”ңв–’ora de Guadalupe, y localizado entre las calles del Escultor Palao, de Nuestra Seв”ңв–’ora del Salz (telв”ңв”Ӯn de fondo edilicio de la imagen), de Terrer y de Demetrio Galв”ңГӯn Bergua. Este campo de tierra del barrio de Las Delicias estuvo activo hasta que en 1983 el planeamiento urbanв”ңВЎstico ubicв”ңв”Ӯ en este emplazamiento el Colegio Pв”ңв•‘blico Ciudad de Zaragoza y el homв”ңв”Ӯnimo Pabellв”ңв”Ӯn Deportivo Municipal. Fuente visual: Antonio Calvo Pedrв”ңв”Ӯs, AMZ.', 1981, 1981, 1981, 'Anos 80', 'DELICIAS', 41.64850400, -0.91474000, '0101000020E61000002FFA0AD28C45EDBFA0A9D72D02D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38486173246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38486173246.webp', 'https://www.flickr.com/photos/zaragozaantigua/38486173246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23698, 'Calle de Terrer 1977', 'Escena nival capturada desde el bloque de la calle de Barcelona, tramo actualmente denominado calle de la Villa de Andorra, esquinero con la calle de Sigв”ңв•қв”ңВ®s, y centrada en los inmuebles de los nв”ңв•‘meros 2-4 de la calle de Terrer, en cuyos bajos y desde 1972 destaca el Centro Comercial Delicias, mercado de proximidad que perdura. Ante в”ңВ®l pasa un autobв”ңв•‘s urbano de la lв”ңВЎnea 31. Torrero-Delicias. En el solar de primer tв”ңВ®rmino, ocupado por camiones, serв”ңГӯ construido luego el Centro de Salud Universitas. A la izquierda, la calle de Nuestra Seв”ңв–’ora del Salz, donde destaca el Campo de Nuestra Seв”ңв–’ora de Guadalupe para la prв”ңГӯctica futbolв”ңВЎstica, hasta que en 1983 el planeamiento urbanв”ңВЎstico de la zona dedicв”ңв”Ӯ estos terrenos para el Colegio Pв”ңв•‘blico Ciudad de Zaragoza y el homв”ңв”Ӯnimo Pabellв”ңв”Ӯn Deportivo Municipal. Mв”ңГӯs allв”ңГӯ, bloques de la calle de Demetrio Galв”ңГӯn Bergua.', 1977, 1977, 1977, 'Anos 70', 'DELICIAS', 41.64736600, -0.91368600, '0101000020E61000008E041A6CEA3CEDBF6B459BE3DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15808433362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15808433362.webp', 'https://www.flickr.com/photos/zaragozaantigua/15808433362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23727, 'Galв”ңГӯn Bergua 1978', 'Irrepetible imagen centrada en el montaraz barbecho urbanв”ңВЎstico de la calle Demetrio Galв”ңГӯn Bergua, en el tramo delimitado por las calles de Fray Juan Regla (tras los bloques del fondo), y la del Escultor Palao. Las parcelas de la derecha, recayentes a la calle de Nв”¬В¬ Sв”¬В¬ del Salz, incluyendo el enternecedor acceso a las parcelitas del nв”¬в•‘ 10 A, B, C, D, y E de esa calle, perduran de forma prodigiosa. La terrosa pista de primer plano, por la que caminan algunos vecinos se convertirв”ңГӯ, al tiempo, en la acera de acceso a los modernos bloques de los nв”ңв•‘meros 11-21 de Galв”ңГӯn Bergua. Fuente visual: Banco de Imв”ңГӯgenes/Asociaciв”ңв”Ӯn de Vecinos Barrio de San Josв”ңВ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'DELICIAS', 41.64933200, -0.91571500, '0101000020E6100000CB9C2E8B894DEDBF861F9C4F1DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32348482514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32348482514.webp', 'https://www.flickr.com/photos/zaragozaantigua/32348482514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21226, 'Caballos en el Ebro 1905', '"Partida de la balsa", fotografв”ңВЎa del teniente Eladio Pascual, 1905. Imagen perteneciente al reportaje "Prв”ңГӯcticas de paso de rв”ңВЎos realizadas por el Regimiento Lanceros del Rey, 1в”¬в•‘ de Caballerв”ңВЎa". En este caso, se trata de pasar de una orilla a otra del Ebro, mediante una balsa construida con sacas rellenas de paja. Los caballos atravesaron el rв”ңВЎo a nado. Al fondo parece vislumbrarse la silueta del Pilar. La zona donde se realizan las maniobras es, probablemente, aguas abajo, entre las desembocaduras de los rв”ңВЎos Gв”ңГӯllego y Huerva, que tambiв”ңВ®n fueron objeto de prв”ңГӯcticas militares en este mismo conjunto de ejercicios. Fuente: Revista La ilustraciв”ңв”Ӯn Espaв”ңв–’ola y Americana, 15-9-1905. hemerotecadigital.bne.es/', 1905, 1905, 1905, 'Anos 1900', 'LAS FUENTES', 41.65237400, -0.86017500, '0101000020E610000011C7BAB88D86EBBF5F61C1FD80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18465102323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18465102323.webp', 'https://www.flickr.com/photos/zaragozaantigua/18465102323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23741, 'Calle de N.в”¬В¬ S.в”¬В¬ del Salz 1976', 'Imagen capturada a la altura del nв”ңв•‘mero 41 de la calle de N.в”¬В¬ S.в”¬В¬ del Salz y centrada en una singular pintada que proclama "в”¬ГӯViva el alcalde!" y aparece firmada por la no menos singular facciв”ңв”Ӯn ultraderechista "Alianza anticomunista/anticapitalista", como forma de respaldar al regidor Miguel Merino Pineda en el denominado "conflicto de las vallas", cuando durante la urbanizaciв”ңв”Ӯn del Polв”ңВЎgono 22 (terrenos de la antigua fв”ңГӯbrica de Criado y Lorenzo) la empresa constructora "CYLSA" (Criado y Lorenzo, SA) cerraba los portones de obra al final de cada jornada que permitв”ңВЎan el paso por el recinto vallado de unos 50.000 metros cuadrados, cortando asв”ңВЎ los pasos usados por los peatones que debв”ңВЎan buscar otra ruta dando enorme rodeo. En primer tв”ңВ®rmino, un SEAT 124, y al fondo la esquina con la calle del Escultor Palao.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64857600, -0.91450400, '0101000020E610000038F581E49D43EDBF397CD28904D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54252959002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54252959002.webp', 'https://www.flickr.com/photos/zaragozaantigua/54252959002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25980, 'Delicias 1968', 'Desde las once alturas del nв”¬в•‘ 9 de la calle de Demetrio Galв”ңГӯn Bergua, panorв”ңГӯmica del barrio de Las Delicias. En primer tв”ңВ®rmino, la calle de Nuestra Seв”ңв–’ora del Salz, con detalle del nв”¬в•‘ 16, en contrucciв”ңв”Ӯn, y del singular acceso a las fincas A, B, C y D del nв”¬в•‘ 8, y las A, B, C, D, y E del nв”¬в•‘ 10. Detrв”ңГӯs, la calle de Mosв”ңВ®n Andrв”ңВ®s Vicente, cruzada de izquierda a derecha por las calles de Fray Luis Regla, de Antonio Bravo, de Eloy Martв”ңВЎnez, y del Escultor Palao. Aв”ңв–’os despuв”ңВ®s, algunos inmuebles de esta calle serв”ңВЎan sustituidos por bloques mв”ңГӯs altos, como en el caso de los nв”ңв•‘meros 12-14, 18, y 20. A la derecha, traseras de los bloques de la plaza, actual calle, de la Ciudadela, que eclipsan a los norteв”ңв–’os pabellones de Dronda, y de Santa Ana, del Hospital Psiquiв”ңГӯtrico Nuestra Seв”ңв–’ora del Pilar. Al fondo, la perspectiva permite ver las cuatro torres del Pilar, con la cв”ңв•‘pula mayor en medio. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.64736100, -0.91414300, '0101000020E610000027C11BD2A840EDBF59DAA9B9DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15236729062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15236729062.webp', 'https://www.flickr.com/photos/zaragozaantigua/15236729062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21534, 'Barrio de la Romareda 1927', 'Panorв”ңГӯmica del barrio de la Romareda. Este conjunto conformв”ңв”Ӯ, con otros similares adyacentes, el actual barrio de Las Delicias. Se situв”ңв”Ӯ en traseras de la Estaciв”ңв”Ӯn de Campo Sepulcro, en la parte comprendida entre las actuales avenidas de Valencia y Madrid. Tomaba su nombre de la acequia alta de la Romareda. Fuente visual de la imagen: Mв”¬В¬ Pilar Biel Ibв”ңГӯв”ңв–’ez, Zaragoza y la industrializaciв”ңв”Ӯn: la arquitectura industrial 1875-1936, IFC, 2004.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.64828000, -0.90216600, '0101000020E61000003605323B8BDEECBF5053CBD6FAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19472107288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19472107288.webp', 'https://www.flickr.com/photos/zaragozaantigua/19472107288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21714, 'Ciudad Jardв”ңВЎn 1936', 'Emplazamiento de Casas Baratas que se proyecta construir en la zona de ensanche de Miralbueno, secciв”ңв”Ӯn 6в”¬В¬. Zaragoza, mayo de 1936. Fuente: AMZ.', 1936, 1936, 1936, 'Anos 30', 'DELICIAS', 41.64617800, -0.90247800, '0101000020E6100000ED80EB8A19E1ECBF85B2F0F5B5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18934629413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18934629413.webp', 'https://www.flickr.com/photos/zaragozaantigua/18934629413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21716, 'Ciudad jardв”ңВЎn 1934', '"Plano Emplazamiento de 500 casas baratas que se proyectan en la Zona de Ensanche de Miralbueno [Ciudad Jardв”ңВЎn]", septiembre de 1934. Fuente: AMZ.', 1934, 1934, 1934, 'Anos 30', 'DELICIAS', 41.64617800, -0.90247800, '0101000020E6100000ED80EB8A19E1ECBF85B2F0F5B5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19554355432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19554355432.webp', 'https://www.flickr.com/photos/zaragozaantigua/19554355432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21912, 'Campo Sepulcro 1939', 'Imagen capturada en el gran complejo fabril de la empresa Material Mв”ңв”Ӯvil y Construcciones sita al oeste de la estaciв”ңв”Ӯn de ferrocarril de Campo Sepulcro y centrada en la ceremonia de la "Fiesta de la exaltaciв”ңв”Ӯn del Trabajo" instituida por el Fuero del Trabajo y que se debв”ңВЎa celebrar obligatoriamente el 18 de julio coincidiendo con el aniversario del "Glorioso Alzamiento Nacional". Esta fiesta respondв”ңВЎa al "nuevo" concepto del trabajo como "fiesta de la hermandad y de la unidad de los productores incorporada en la alegrв”ңВЎa unв”ңГӯnime de la Patria al festejar el 18 de julio". De esa forma, los "productores" tenв”ңВЎan que celebrar ese dв”ңВЎa "en agrupaciв”ңв”Ӯn ordenada", reunidos en sus respectivas empresas y dispuestos "conforme a la jerarquв”ңВЎa natural de la producciв”ңв”Ӯn" en lugar presidido por la Bandera Nacional, las del "Movimiento" y el retrato del "Caudillo" en sitio de honor, y si fuera posible, con mв”ңв•‘sica de los respectivos himnos. Cerraban la fiesta los gritos reglamentarios de "ESPAв”ңГҰA, UNA; ESPAв”ңГҰA, GRANDE; ESPAв”ңГҰA, LIBRE; в”¬ГӯARRIBA ESPAв”ңГҰA!" En la imagen, vista en altura del momento en que los "productores", dispuestos en el gran pasillo central flanqueado por las naves y talleres de esta empresa, saludan con el reglamentario brazo en alto a la enseв”ңв–’a nacional que preside el acto. Al fondo, traseras de la larga calle de Roche y campos de cultivo que flanquean la carretera de Zaragoza a Valencia hasta los pabellones del cuartel de Palafox.', 1939, 1939, 1939, 'Anos 30', 'DELICIAS', 41.65061300, -0.89723100, '0101000020E6100000D3A23EC91DB6ECBF1DAD6A4947D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52156383140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52156383140.webp', 'https://www.flickr.com/photos/zaragozaantigua/52156383140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22181, 'Calle Escosura 1959', 'Imagen aв”ңВ®rea sobrevolando el antiguo entorno, en primer tв”ңВ®rmino, de las calles Escosura, Tarragona y в”ңГјvila, para obtener una buena perspectiva del complejo fabril de Material Mв”ңв”Ӯvil y Construcciones, junto a la estaciв”ңв”Ӯn de Campo Sepulcro y el barrio de Cariв”ңв–’ena, a la derecha. A la izquierda, indefinido enlace con el barrio de Delicias. Al fondo, la Aljaferв”ңВЎa y la Almozara. Fuente visual: fondo fotogrв”ңГӯfico TAF Helicв”ңв”Ӯpteros SA , en Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.64892300, -0.89843100, '0101000020E61000006CCD565EF2BFECBFA54FABE80FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31895640275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31895640275.webp', 'https://www.flickr.com/photos/zaragozaantigua/31895640275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22249, 'Barrio de la Romareda 1956', 'Imagen capturada desde la altura de las nuevas naves seriadas de los talleres de Material Mв”ңв”Ӯvil y Construcciones, S.A. en terrenos inmediatos al antiguo barrio de la Romareda, que a la izquierda se presenta arbolado y vertebrado por las calles del Moncayo y la antigua de Gascв”ңв”Ӯn, actual de Escoriaza. Al fondo, inmuebles de la calles de Salamanca, Tarragona, в”ңГјvila y Escosura.', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65070900, -0.89667300, '0101000020E6100000429946938BB1ECBF3F1BB96E4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52321858824.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52321858824.webp', 'https://www.flickr.com/photos/zaragozaantigua/52321858824/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21544, 'Reformatorio Buen Pastor 1921', 'Dibujo de Regino Borobio del Reformatorio del Buen Pastor de Zaragoza, 1921. La Torre Ramona se acondicionв”ңв”Ӯ para reformatorio en 1917 y dejв”ңв”Ӯ de funcionar como tal en 1955. Tras funcionar como colegio de monjas, el edificio sigue en pie en la calle de Marв”ңВЎa de Aragв”ңв”Ӯn del barrio de Las Fuentes en 2015. Fuente: Eloy Fernв”ңГӯndez Clemente, "Gente de orden", Ibercaja, 1995.', 1921, 1921, 1921, 'Anos 20', 'LAS FUENTES', 41.64094400, -0.86212600, '0101000020E61000006000E1438996EBBFA148F7730AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20124614286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20124614286.webp', 'https://www.flickr.com/photos/zaragozaantigua/20124614286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22252, 'Campo Sepulcro 1953', 'Imagen capturada en el interior de una de las naves de la factorв”ңВЎa de Material Mв”ңв”Ӯvil y Construcciones sita en el barrio de Cariв”ңв–’ena o de la Romareda, junto a la estaciв”ңв”Ӯn de Campo Sepulcro. La escena se centra en uno de los dos chasis del microcoche "Pulga" aquв”ңВЎ carrozado, una versiв”ңв”Ӯn mв”ңГӯs moderna del original proyecto mallorquв”ңВЎn patentado en 1950 y desarrollado en Ontinent (Valencia). Los microcoches o coches diminutos, algunos de ellos sustentados sobre tres ruedas como este "Pulga", conocieron un singular desarrollo en la Espaв”ңв–’a de la larga posguerra (aв”ңв–’os 50 y 60), siendo este modelo "Pulga" uno de los pioneros, si bien su producciв”ңв”Ӯn fue muy modesta. Tras el vehв”ңВЎculo de primer tв”ңВ®rmino, uno de los vagones ferroviarios fabricados en esta fв”ңГӯbrica.', 1953, 1953, 1953, 'Anos 50', 'DELICIAS', 41.65061300, -0.89723100, '0101000020E6100000D3A23EC91DB6ECBF1DAD6A4947D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54723497577.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54723497577.webp', 'https://www.flickr.com/photos/zaragozaantigua/54723497577/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22262, 'Trolebв”ңв•‘s 1966', '1966. El Trolebв”ңв•‘s 51 de la Lв”ңВЎnea "Ciudad Jardв”ңВЎn" haciendo la curva que desde Franco y Lв”ңв”Ӯpez le permite seguir por Duquesa de Villahermosa para llegar a su destino en la Ciudad Jardв”ңВЎn, dar la vuelta en la calle Pedro de Luna, y coger San Juan Bosco para retornar a la Terminal de la Plaza de Santa Engracia. En primer tв”ңВ®rmino, un taxi caracterв”ңВЎstico de la в”ңВ®poca en Zaragoza. A la izquierda, el Colegio de las "Josefinas" (Hijas de San Josв”ңВ®). Al fondo, las naves del inmenso polв”ңВЎgono de Carde y Escoriaza, que llegaban hasta lo que luego, ya urbanizada, serв”ңГӯ la Plaza de Roma', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64828000, -0.90216600, '0101000020E61000003605323B8BDEECBF5053CBD6FAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14788184428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14788184428.webp', 'https://www.flickr.com/photos/zaragozaantigua/14788184428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22335, 'Calle Santander 1969', 'Pintura de Eduardo Laborda titulada "La calle Santander de Zaragoza". Posiblemente se trate del nuevo bloque de viviendas del nв”¬в•‘ 32, esquina con la calle Josв”ңВ® Pascasio Escoriaza, tan chocante con el hasta entonces mв”ңГӯs humano en escala entorno de la antigua estaciв”ңв”Ӯn de ferrocarril de Campo Sepulcro, con sus parcelas, huertos traseros... Al fondo, tal vez los bloques de las viviendas militares de Anselmo Clavв”ңВ®, frente a la estaciв”ңв”Ӯn. Fuente visual: "Eduardo Laborda. Simbolismo barroco", Cajalв”ңв”Ӯn, 2006.', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.64916200, -0.89666200, '0101000020E6100000471CB28174B1ECBF29E78BBD17D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19537993041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19537993041.webp', 'https://www.flickr.com/photos/zaragozaantigua/19537993041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22564, 'Plaza de Roma 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 08/09/1974. Los sucesivos proyectos de "Casas Baratas" y de ordenaciв”ңв”Ӯn urbanв”ңВЎstica del crecimiento de la ciudad por el oeste dejaron pocas realidades en la zona del original barrio de la Romareda, o de Cariв”ңв–’ena, salvo la aislada intervenciв”ңв”Ӯn de la "Ciudad Jardв”ңВЎn". Habв”ңВЎa demasiados intereses especulativos en su contra y, ademв”ңГӯs, la omnipotente presencia del enorme complejo fabril de Escoriaza, en las traseras de Campo Sepulcro, condicionaba cualquier actuaciв”ңв”Ӯn. Cuando esta fв”ңГӯbrica se deslocalizв”ңв”Ӯ a otra ubicaciв”ңв”Ӯn, se abrieron nuevas calles, y la urbanizaciв”ңв”Ӯn de la zona (grandes bloques de viviendas) avanzв”ңв”Ӯ rв”ңГӯpidamente al albur del desarrollismo sesentero. Asв”ңВЎ, la plaza de Roma y la estratв”ңВ®gica Urbanizaciв”ңв”Ӯn Parque Roma vieron la luz en fecha tan reciente como 1972, en un entorno irreconocible para quien recordara el paso del antiguo ferrocarril de Cariв”ңв–’ena justo aquв”ңВЎ. En la imagen, la plaza de Roma vista en altura, con la calle Vicente Berdusв”ңГӯn a la derecha, luego la calle Italia, y el arranque, a la izquierda, de Duquesa Villahermosa.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.64948200, -0.89899000, '0101000020E610000014CB2DAD86C4ECBF9BABE63922D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15231545788.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15231545788.webp', 'https://www.flickr.com/photos/zaragozaantigua/15231545788/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22585, 'Calle Delicias c.1973', 'Vista de la calle Delicias de Zaragoza desde su embocadura en la calle Duquesa Villahermosa. A la izquierda, colegio pв”ңв•‘blico Andrв”ңВ®s Manjв”ңв”Ӯn. Fuente: www.facebook.com/photo.php?fbid=1680995642145619&set=...', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.64792500, -0.90372300, '0101000020E61000008693347F4CEBECBF62A1D634EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15647214881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15647214881.webp', 'https://www.flickr.com/photos/zaragozaantigua/15647214881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22599, 'D. Pedro de Luna 1975', 'El denominado "Dв”ңВЎa del Ahorro", celebrado a bombo y platillo como si de un ejercicio de participaciв”ңв”Ӯn democrв”ңГӯtica en la economв”ңВЎa se tratara, era sin embargo algo mв”ңГӯs pedestre, y menos revolucionario: un puro ejercicio de captaciв”ңв”Ӯn del ahorro de los pobres por parte de las entidades gestoras del dinero ajeno que, a cambio, "regalaban" libros sobre recuerdos regionalistas entraв”ңв–’ables y amables, algunos sesudos libros de historia para decorar estanterв”ңВЎas, frescas colonias de garrafв”ңв”Ӯn, et cetera. De esta forma, y otras mв”ңГӯs, la entidad de ahorro que aparece en la imagen consiguiв”ңв”Ӯ cuatriplicar sus recursos ajenos en pocos aв”ңв–’os, convirtiв”ңВ®ndose en la tercera de las Cajas Confederadas espaв”ңв–’olas. Otro asunto muy distinto era en quв”ңВ® invertв”ңВЎa luego esos dineros, siquiera si lo hacв”ңВЎa en la "regiв”ңв”Ӯn aragonesa" (y Rioja, por supuesto), y con quв”ңВ® resultados. En la imagen, una de las filas, o "colas" que se organizaban a la entrada de estas entidades de ahorro en esos dв”ңВЎas tan seв”ңв–’alados, de "fiesta del ahorro". La clase social de quienes forman la cola es esa que estв”ңГӯ acostumbrada a hacer cola siempre, incluso para dar su dinero a un interв”ңВ®s ridв”ңВЎculo, o a cambio de un libro de cocina. Estamos en la que fuera calle de Josв”ңВ® Arias, luego denominada D. Pedro de Luna, casi en la esquina con el antiguo Camino de la Mosquetera y la acequia de la Romareda, luego Duquesa Villahermosa. La agencia de la entonces caja, hoy banco, sigue en el mismo sitio. Lo que ha desaparecido es el edificio de ladrillo de su izquierda. Fuente: foto Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.64822400, -0.90329200, '0101000020E61000003CA1D79FC4E7ECBFBC3D0801F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18582357213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18582357213.webp', 'https://www.flickr.com/photos/zaragozaantigua/18582357213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22742, 'Calle de Vicente Berdusв”ңГӯn 1973', 'A lomos de un mulo, un avezado jinete (el detalle del modelo de calzado que gasta lo delata) cruza con resoluciв”ңв”Ӯn por el final de la calle de Vicente Berdusв”ңГӯn y se encamina hacia la calle de la Duquesa de Villahermosa. De fondo, portal de ingreso al moderno bloque esquinero del nв”¬в•‘ 24 de Vicente Berdusв”ңГӯn, actual nв”¬в•‘ 46. A la izquierda, local reservado para instalar una sucursal de la Caja de Ahorros de la Inmaculada. A la derecha, local comercial donde aв”ңв–’os despuв”ңВ®s se constituirв”ңГӯ la Ferreterв”ңВЎa Arias. A espaldas del fotв”ңв”Ӯgrafo, el antiguo y gran complejo industrial de Material Mв”ңв”Ӯvil y Construcciones, ya redenominada Construcciones y Auxiliar de Ferrocarriles, y en proceso de reubicaciв”ңв”Ӯn en unas nuevas instalaciones en la avenida de Cataluв”ңв–’a.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.64983700, -0.89894600, '0101000020E61000002CD7DB662AC4ECBF895DDBDB2DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31800517187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31800517187.webp', 'https://www.flickr.com/photos/zaragozaantigua/31800517187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22751, 'Calle de Escosura 1976', 'Imagen del calificado como "в”ңв•‘ltimo в”ңГӯrbol de Escosura", que tambiв”ңВ®n fue finalmente arrancado durante las obras de vialidad y aguas que tras varios meses renovaron el abastecimiento y saneamiento de esta antigua calle, antes denominada de Roche. El в”ңГӯrbol estaba ubicado a la altura del nв”¬в•‘ 38-B, en la imagen flanqueado por dos parcelas luego sustituidas por modernos edificios. Hacia la derecha, direcciв”ңв”Ӯn avenida de Valencia. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64798500, -0.89842000, '0101000020E61000007250C24CDBBFECBF37A6272CF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32611850383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32611850383.webp', 'https://www.flickr.com/photos/zaragozaantigua/32611850383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23041, 'Calle de Vicente Berdusв”ңГӯn 1994', 'Imagen capturada durante la urbanizaciв”ңв”Ӯn de la calle de Vicente Berdusв”ңГӯn y el tramo de la calle de Escoriaza y Fabro comprendido entre esta calle y la avenida de Madrid. En primer tв”ңВ®rmino, vehв”ңВЎculos aparcados sobre los solares de antiguas parcelas derribadas entre las calles de Romв”ңГӯn Izuzquiza y de Fuendetodos, donde a finales de esta dв”ңВ®cada se construirв”ңВЎa el actual inmueble del nв”¬в•‘ 30 de la calle de Vivente Berdusв”ңГӯn. Hacia el fondo y a la izquierda, bloques de viviendas del camino de la Mosquetera y de las calles de Hilariв”ңв”Ӯn Eslava. Navas de Tolosa y Doв”ңв–’a Blanca de Navarra. Al fondo, bloques de la calle de Fuenterrabв”ңВЎa. A la derecha, bloques de la urbanizaciв”ңв”Ӯn Parque Roma. La urbanizaciв”ңв”Ӯn de esta zona incluв”ңВЎa la renovaciв”ңв”Ӯn del servicio de alcantarillado para resolver las crв”ңв”Ӯnicas deficiencias de evacuaciв”ңв”Ӯn de aguas pluviales que se acumulaban en el paso a desnivel de la avenida de Madrid.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65087700, -0.89879700, '0101000020E6100000EFC517EDF1C2ECBFFB5B02F04FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50380195132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50380195132.webp', 'https://www.flickr.com/photos/zaragozaantigua/50380195132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23122, 'Vв”ңВЎa Univв”ңВ®rsitas 2006', 'Foto: Marв”ңВЎa Torres-Solanot. Construcciв”ңв”Ӯn del Centro Cв”ңВЎvico Esquinas del Psiquiв”ңГӯtrico, en la Vв”ңВЎa Univв”ңВ®rsitas 30-32. En 2003 fueron adjudicadas las obras de este entorno por parte del Gobierno de Aragв”ңв”Ӯn al grupo Bruesa. Los equipamientos municipales incluidos fueron un pabellв”ңв”Ӯn polideportivo, un teatro y este centro, inaugurado en 2010. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.64679300, -0.90780100, '0101000020E6100000C7D5C8AEB40CEDBF1024EF1CCAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31130296583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31130296583.webp', 'https://www.flickr.com/photos/zaragozaantigua/31130296583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23317, 'Plaza de Roma 1968', '1968. Familia Roldв”ңГӯn. "Gravera (Plaza Roma) vista desde la C/ Italia". La urbanizaciв”ңв”Ӯn del polв”ңВЎgono industrial de Carde y Escoriaza en las traseras de la Estaciв”ңв”Ӯn Campo Sepulcro iba a suponer que la ciudad tuviera una "Plaza de Roma" modelada como eje entre Duquesa Villahermosa, y las nuevas calles de Santander y Vicente Berdusв”ңГӯn, ademв”ңГӯs de propiciar el crecimiento de altos y modernos bloques residenciales. En la imagen, familiar posado a la entrada de la calle Desiderio Escosura, desde lo que mв”ңГӯs tarde serв”ңГӯ la Plaza de Roma, con el enorme bloque de entrada a la calle en plena construcciв”ңв”Ӯn. Al fondo, el no menos impresionante Edificio Torresol. A la izquierda, insв”ңв”Ӯlita vista de las calles Tarragona y в”ңГјvila. Antes, restos piqueteados de las naves de Carde y Escoriaza, utilizados como parque infantil de juego, como pasaba en todos los barrios de la periferia de la ciudad, sin que aparentemente ninguna madre entrara en coma.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.64898500, -0.89908700, '0101000020E6100000B247A81952C5ECBF1B4CC3F011D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14783752810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14783752810.webp', 'https://www.flickr.com/photos/zaragozaantigua/14783752810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23693, 'Hospital Psiquiв”ңГӯtrico 1964', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 4/7/1964. Instalaciones del Hospital Psiquiв”ңГӯtrico Nuestra Seв”ңв–’ora del Pilar de Zaragoza (manicomio). Al fondo, la capilla que aв”ңв•‘n se levanta en el parque. En primer plano, busto con arbusto de D. Manuel Dronda, prв”ңв”Ӯcer local fallecido el 1 de diciembre de 1899, que habв”ңВЎa dedicado tiempo y fortuna a la mejora del manicomio, comprando terrenos y mandando construir pabellones. La DPZ acordв”ңв”Ӯ que a su cadв”ңГӯver se le hiciera una mascarilla funeraria (por el escultor Palao) para un busto fundido en metal que honrara su memoria en lugar principal del establecimiento.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.64685600, -0.91068400, '0101000020E6100000E2B19FC55224EDBF569C6A2DCCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024451200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024451200.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024451200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23702, 'San Simeв”ңв”Ӯn, o los Gigantes en el manicomio 1925', 'Se estiman en unos 400 los tipos de trastornos mentales que acompaв”ңв–’an al ser humano en su trв”ңГӯnsito por este valle de lв”ңГӯgrimas. Entre los mв”ңГӯs comunes se encuentran los trastornos afectivos (depresiones y distimias), de ansiedad (fobias, angustias, obsesivos compulsivos, somatizaciв”ңв”Ӯn ...), adicciones (innв”ңв•‘meras), trastornos psicв”ңв”Ӯticos (esquizofrenia, bipolaridad ...), y aquellos asociados a la tercera edad (demencias, trastornos del sueв”ңв–’o ...) A pesar de sus enormes complejidades, la "locura", como simplificaciв”ңв”Ӯn extrema del asunto, es interpretada culturalmente como un defecto, un estigma: loco es quien ha perdido la razв”ңв”Ӯn. Desde que en la edad media se pretendв”ңВЎa sanar al loco mediante la "extracciв”ңв”Ӯn de la piedra de la locura", o cirugв”ңВЎa mayor, han sido varias las estrategias de las polв”ңВЎticas pв”ңв•‘blicas a la hora de afrontar este tema, aunque la mв”ңГӯs generalizada ha sido la asociada con el estigma que le acompaв”ңв–’a: poner al loco fuera de circulaciв”ңв”Ӯn como medida de saneamiento social, y recluirlo en un hospital, junto a los pobres. Hasta que en 1914 se desarrolla la enfermerв”ңВЎa mental de carв”ңГӯcter laico, y en los aв”ңв–’os 20 se crea la Escuela Nacional de Sanidad y la Escuela de Psiquiatrв”ңВЎa, los tratamientos consistв”ңВЎan en un internado donde se velaba por la salud corporal, la alimentaciв”ңв”Ӯn y la educaciв”ңв”Ӯn en la doctrina cristiana. En Zaragoza, la DPZ acordв”ңв”Ӯ construir segв”ңв•‘n estos preceptos, en 1873, un Manicomio Modelo en la Granja de Nв”¬В¬. Sв”¬В¬. del Pilar, en el Terminillo. Hasta entonces, los asilados estaban ingresados en el Hospital de Gracia. Una vez terminados, los nuevos pabellones tenв”ңВЎan capacidad para 600 enfermos, con casi 4 hectв”ңГӯreas de buena huerta alrededor. En 1912 este Manicomio pasв”ңв”Ӯ a depender del Estado. En la imagen, el Rey y la Reina encabezan la tradicional comparsa de Gigantes en los jardines y pabellones del Manicomio, para fiestear a los internos. в”ңГ«stos observan atentamente a los inanimados artefactos despojados de sus titiriteros, mientras que uno de ellos pref', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.64690100, -0.91150000, '0101000020E61000005EBA490C022BEDBFF65FE7A6CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18484244615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18484244615.webp', 'https://www.flickr.com/photos/zaragozaantigua/18484244615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23704, 'Calle Delicias 1925', 'Fuente: Mв”¬В¬ Pilar Biel Ibв”ңГӯв”ңв–’ez, Zaragoza y la industrializaciв”ңв”Ӯn: la arquitectura industrial 1875-1936, IFC, 2004.', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65027300, -0.90474300, '0101000020E6100000211E8997A7F3ECBF643C4A253CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19039560603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19039560603.webp', 'https://www.flickr.com/photos/zaragozaantigua/19039560603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23705, 'Calle Sangenв”ңВЎs 1924', 'Acceso de los Talleres Chalmeta en 1924. Fundados en 1919, producв”ңВЎan envases metв”ңГӯlicos, artв”ңВЎculos de hojalaterв”ңВЎa y estampaciones sobre metales. Estaban situados en la calle de Antonio Sangenв”ңВЎs 40 del barrio de las Delicias. Fuente: La Esfera, 3 de enero de 1925.', 1924, 1924, 1924, 'Anos 20', 'DELICIAS', 41.65013000, -0.90335800, '0101000020E6100000198F52094FE8ECBF0113B87537D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19845170688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19845170688.webp', 'https://www.flickr.com/photos/zaragozaantigua/19845170688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23707, 'Isabel de Borbв”ңв”Ӯn 1913', 'Visita de la infanta Isabel de Borbв”ңв”Ӯn, "la Chata", hija de la reina Isabel II, al Manicomio de Zaragoza en julio de 1913. Le acompaв”ңв–’an el prior del Manicomio de Nuestra Seв”ңв–’ora del Pilar, la superiora y el mв”ңВ®dico director, dr. Gimeno Riera. Fuente: Fotografв”ңВЎa de Aurelio Grasa publicada en el libro "Aurelio Grasa 1893-1972", Galerв”ңВЎa Costa, 3, 1976. Pв”ңГӯgina 37. Formв”ңв”Ӯ parte de la exposiciв”ңв”Ӯn conmemorativa celebrada en dicha galerв”ңВЎa en 1978. Tambiв”ңВ®n fue publicada en la pв”ңГӯgina 53 del catв”ңГӯlogo "Aurelio Grasa reportero grв”ңГӯfico 1910-1917", RSFZ, Galerв”ңВЎa Costa,3. Zaragoza 2003. Fotografia publicada en Heraldo de Aragв”ңв”Ӯn el 23 de julio de 1913, en ABC el 25 de julio de 1913. El periв”ңв”Ӯdico ABC conserva una copia de esa fotografв”ңВЎa de Aurelio Grasa que el mismo enviв”ңв”Ӯ para su publicaciв”ңв”Ӯn. www.aureliograsa.es', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.64716400, -0.91050300, '0101000020E6100000CD1DFD2FD722EDBF03931B45D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21280020406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21280020406.webp', 'https://www.flickr.com/photos/zaragozaantigua/21280020406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23710, 'Calle Delicias aв”ңв–’os 80', 'Foto: Vв”ңВЎctor M. Soriano. Vista de la calle Delicias de Zaragoza, a la altura del nв”ңв•‘mero 34. A la izquierda, calle Bв”ңВ®lgica. Al fondo, avenida de Madrid. En 1990, se remodelв”ңв”Ӯ y convirtiв”ңв”Ӯ en peatonal. Fuente visual: www.facebook.com/photo.php?fbid=1082365388459063&set=...', 1980, 1980, 1989, 'Anos 80', 'DELICIAS', 41.65100400, -0.90513900, '0101000020E61000004FB16A10E6F6ECBF58C85C1954D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22357529120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22357529120.webp', 'https://www.flickr.com/photos/zaragozaantigua/22357529120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23711, 'Calle de Garcв”ңВЎa Sв”ңГӯnchez 1976', 'Parada terminal que enlazaba las lв”ңВЎneas 22 y 24 del autobв”ңв•‘s urbano entre Las Fuentes y Las Delicias, en la calle de Josв”ңВ® Garcв”ңВЎa Sв”ңГӯnchez. Al fondo, el colegio de las Hijas de San Josв”ңВ®, Al fondo, el colegio de las Hijas de San Josв”ңВ®, chaflanero entre Duquesa Villahermosa y Marcelino de Unceta. La huelga que anuncia el cartel durв”ңв”Ӯ del 8 al 11 de octubre, cuando se llegв”ңв”Ӯ a un principio de acuerdo. Por si acaso, el domingo 10 salieron autobuses conducidos por personal del Parque Mв”ңв”Ӯvil de los ministerios civiles, y microbuses por chв”ңв”Ӯferes del Ejв”ңВ®rcito de Tierra.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64841800, -0.90014800, '0101000020E6100000F2E9B12D03CEECBFA1116C5CFFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24006878943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24006878943.webp', 'https://www.flickr.com/photos/zaragozaantigua/24006878943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23737, 'Manicomio 1913', 'Visita de la infanta Isabel de Borbв”ңв”Ӯn, "la Chata", hija de la reina Isabel II, al Manicomio de Nuestra Seв”ңв–’ora del Pilar en el Terminillo, en julio de 1913. Le acompaв”ңв–’an el prior de los Hermanos de San Juan de Dios y la superiora de las Hermanas de la Caridad de Santa Ana, sor Amalia Porcano, ademв”ңГӯs del espigado subdirector mв”ңВ®dico, doctor Joaquв”ңВЎn Gimeno Riera. A la derecha y en segundo plano, el arzobispo Juan Soldevila, siempre interesado en todo lo relacionado con el Terminillo. A la izquierda, uno de los lacayos del coche de caballos en que se desplazaba la infanta por la ciudad en su estancia.', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.64731800, -0.90945100, '0101000020E61000005A10CAFB381AEDBF5A0EF450DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50783415323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50783415323.webp', 'https://www.flickr.com/photos/zaragozaantigua/50783415323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23740, 'Barrio de Roche 1927', 'Imagen capturada en el barrio de Roche, resultante de la parcelaciв”ңв”Ӯn a principios de los aв”ңв–’os 20 del campo de Juan Roche sito en una perifв”ңВ®rica ubicaciв”ңв”Ӯn entre la carretera de Valencia, la estaciв”ңв”Ӯn de Cariв”ңв–’ena y los talleres de Material Mв”ңв”Ӯvil y Construcciones (hacia el fondo). La de la imagen se trataba probablemente de la parcela ya construida y con el numeral 13 de este barrio particular de una sola calle. Tras el 18 de julio de 1936 la calle serв”ңВЎa redenominada de Desiderio Escosura. Actualmente esta localizaciв”ңв”Ӯn se corresponderв”ңВЎa con el punto donde la calle del Obispo Tajв”ңв”Ӯn cruza la de Escosura.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.64769500, -0.89843200, '0101000020E610000083C13577F4BFECBF306475ABE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52324354983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52324354983.webp', 'https://www.flickr.com/photos/zaragozaantigua/52324354983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24030, 'Calle Duquesa Villahermosa 2003', 'Foto: Beatriz Benedicto. Entorno conocido como "Esquinas del Psiquiв”ңГӯtrico", con la calle de la Duquesa de Villahermosa en el centro, atravesв”ңГӯndolo de izquierda a derecha. Allв”ңВЎ estв”ңГӯn situadas las ferias del barrio de las Delicias. Entre 2007 y 2011, el entorno se urbanizarв”ңГӯ con equipamientos pв”ңв•‘blicos y viviendas. Al fondo a la derecha, Vв”ңВЎa Universitas. Fuente: www.facebook.com/photo.php?fbid=532016703802554&set=g...', 2003, 2003, 2003, 'Siglo XXI', 'DELICIAS', 41.64665700, -0.90708000, '0101000020E6100000BB61DBA2CC06EDBF5F5D15A8C5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26208873619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26208873619.webp', 'https://www.flickr.com/photos/zaragozaantigua/26208873619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24217, 'Campo Sepulcro 1949', 'Imagen capturada en la factorв”ңВЎa de Material Mв”ңв”Ӯvil y Construcciones sita junto a la estaciв”ңв”Ӯn de Campo Sepulcro y centrada en la armadura interior de uno de los diez automotores basados en el modelo Renault ABJ-4 encargados por RENFE, que una vez finalizados recibirв”ңВЎan la denominaciв”ңв”Ӯn de ABJ-7 dentro de la serie RENFE 9313-9332. Al fondo, vista parcial del barrio de Cariв”ңв–’ena o de la Romareda con algunos de los singulares "hotelitos" vertebrados en torno a la calle del Moncayo. A la izquierda despunta una de las torrecillas de la antigua fв”ңГӯbrica de chocolates Orв”ңв•‘s entonces ocupada por la sociedad Industrias del Cartonaje S.A.', 1949, 1949, 1949, 'Anos 40', 'DELICIAS', 41.64993900, -0.89733800, '0101000020E610000054A86E2EFEB6ECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54726346345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54726346345.webp', 'https://www.flickr.com/photos/zaragozaantigua/54726346345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25916, 'Duquesa Villahermosa 1969', 'Imagen de la unidad nв”¬в•‘ 74 (un BUT de dos pisos) de la lв”ңВЎnea de trolebuses "Ciudad Jardв”ңВЎn", avanzando por la calle Duquesa Villahermosa hacia el emboque con la calle Pedro Lв”ңв”Ӯpez de Luna, donde iniciar el retorno hacia la plaza de Santa Engracia. La imagen ha sido capturada, casualmente, en la esquina de la calle Don Pedro de Luna. Al fondo, a la izquierda, el gran bloque esquinero con la calle Luis Franco y Lв”ңв”Ӯpez. A la derecha, arbolado de la "Ciudad Jardв”ңВЎn" y, emergente, grв”ңв•‘a de obra, posiblemente del nuevo bloque del nв”¬в•‘ 30 de la calle de Luis Franco y Lв”ңв”Ӯpez. Fuente visual: desequilibros.blogspot.com.es/', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.64802500, -0.90309800, '0101000020E610000000A8E2C62DE6ECBFC5FEB27BF2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30512970254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30512970254.webp', 'https://www.flickr.com/photos/zaragozaantigua/30512970254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25967, 'Huerta del Manicomio 1971', 'En 1873 la DPZ acordв”ңв”Ӯ construir un Manicomio Modelo en la Granja de Ntra. Sra. del Pilar, en el Terminillo. Las obras comenzaron en 1878, pero muchos asilados continuaban ingresados en el antiguo Hospital de Gracia. En 1912 el Manicomio pasв”ңв”Ӯ a depender del Estado. Una vez terminados, los pabellones tenв”ңВЎan capacidad para 600 enfermos, y hasta 4 hectв”ңГӯreas de buena huerta. El Plan Larrodera (1968) recalificв”ңв”Ӯ parte de las zonas verdes para ladrillo, pero la presiв”ңв”Ӯn ejercida durante aв”ңв–’os de movilizaciones, encabezada por las Asociaciones de cabezas de Familia del barrio, consiguieron modificar el Plan, y terreno para el desdoblamiento de Vв”ңВЎa Universitas y Duquesa Villahermosa, y para crear un nuevo Parque. En la imagen, parte de las huertas del Manicomio, la mв”ңГӯs cercana a Duquesa Villahermosa y al Grupo de Viviendas "Severino Aznar" (derecha). En el centro, el Colegio Pв”ңв•‘blico "Josв”ңВ® Marв”ңВЎa Mir". A su izquierda, el bloque de viviendas de la calle Santa Rita de Casia, en la actualidad vecino al CDM "Duquesa Villahermosa". Con la prolongaciв”ңв”Ӯn de Duquesa de Villahermosa y el paso de la Vв”ңВЎa Universitas, esta zona ha vivido una autв”ңВ®ntica mutaciв”ңв”Ӯn. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1971, 1971, 1971, 'Anos 70', 'DELICIAS', 41.64673200, -0.90666100, '0101000020E610000083E0F1ED5D03EDBF6AA33A1DC8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794570428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794570428.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794570428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25973, 'Ciudad Jardв”ңВЎn c.1945', 'AHPZ. Estudio Coyne. Aв”ңв–’os 40. "Ciudad jardв”ңВЎn." Imagen tomada desde cierta altura en la calle Duquesa de Villahermosa, esquina calle Delicias. La que se abre a la izquierda (Lorenzo Calvo de Rozas) es una de las calles interiores de la barriada. Al fondo, la ciudad. Construida entre 1936-39, segв”ңв•‘n proyecto de Miguel в”ңГјngel Navarro. Ideadas dentro de la filosofв”ңВЎa de construcciв”ңв”Ӯn de "Casas Baratas", el franquismo reorientв”ңв”Ӯ su adjudicaciв”ңв”Ӯn, en positivo, hacia gentes leales al nuevo rв”ңВ®gimen, y en negativo hacia quienes no.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.64781500, -0.90343200, '0101000020E6100000AC1DC539EAE8ECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15114921416.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15114921416.webp', 'https://www.flickr.com/photos/zaragozaantigua/15114921416/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25999, 'La Bozada 1991', 'Foto: Archivo Taumar (Irene Taulв”ңВ®s y Rafael Margalв”ңВ®). Vista aв”ңВ®rea del barrio de la Bozada, con el IES Jerв”ңв”Ӯnimo Zurita a la derecha, el parque Avempace en el centro y la Vв”ңВ»a Univв”ңВ®rsitas arriba. En la esquina superior derecha, el Hospital Clв”ңВЎnico. Fuente: www.facebook.com/photo.php?fbid=1687674314789601&set=...', 1991, 1991, 1991, 'Anos 90', 'DELICIAS', 41.64414800, -0.90849800, '0101000020E6100000B267CF656A12EDBF54E4107173D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21785689684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21785689684.webp', 'https://www.flickr.com/photos/zaragozaantigua/21785689684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21567, 'Calle de Alfonso I c.1920', 'En 1918, Celestino Salinero Ena ampliв”ңв”Ӯ y reformв”ңв”Ӯ los originales "Grandes talleres de confecciв”ңв”Ӯn La Casa Blanca" (Alfonso I, 22). La ampliaciв”ңв”Ӯn incorporв”ңв”Ӯ la planta calle del nв”¬в•‘ 24 de la finca, chaflanero con la calle Miguel Molino. La reforma le confiriв”ңв”Ӯ una nueva fachada de conjunto, con el caracterв”ңВЎstico color blanco como seв”ңв–’a de identidad, y unos interiores tambiв”ңВ®n redecorados. En la imagen, la nueva fachada comercial. A la izquierda, la calle Miguel Molino. Fuente visual: aportaciв”ңв”Ӯn de Mariano Lacruz Pв”ңВ®rez de una reproducciв”ңв”Ӯn fotogrв”ңГӯfica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marв”ңВЎa Josв”ңВ® Salinero (nieta de Celestino Salinero).', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23243939405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23243939405.webp', 'https://www.flickr.com/photos/zaragozaantigua/23243939405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21568, '&quot;La Casa Blanca&quot; c.1920', 'Imagen de los "Grandes talleres de confecciв”ңв”Ӯn La Casa Blanca" (Alfonso I, 22-24), de Celestino Salinero Ena, tras la reforma y ampliaciв”ңв”Ӯn de 1918, con un curioso y considerable trampantojo en forma de dibujo que integra toda la primera planta de la finca en el comercio (la parte real era la del fondo, recayente a la calle de Goya, ademв”ңГӯs de toda la planta calle). El chaflв”ңГӯn de primer plano de la imagen, el real (planta calle) y el dibujado (primera planta), en el arranque de la calle Miguel Molino. En la parte superior, cartel indicativo del Hotel de Elв”ңВЎas Cequiel establecido en este inmueble del nв”¬в•‘ 24 de la calle de Alfonso I y del nв”¬в•‘ 2 de la calle de Miguel Molino. Fuente visual: aportaciв”ңв”Ӯn de Mariano Lacruz Pв”ңВ®rez de una reproducciв”ңв”Ӯn fotogrв”ңГӯfica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marв”ңВЎa Josв”ңВ® Salinero (nieta de Celestino Salinero).', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23246383025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23246383025.webp', 'https://www.flickr.com/photos/zaragozaantigua/23246383025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21671, 'Calle de Alfonso I aв”ңв–’os 30', 'Aв”ңв–’os 30 del siglo XX. Colecciв”ңв”Ӯn Vв”ңВЎctor Barв”ңв”Ӯn. Fila de mujeres para comprar en "Las nuevas sederв”ңВЎas". El portal de vecinos entre esa tienda y el Bazar es el nв”ңв•‘mero 26 de la calle, donde vive Dolores Serrat, consejera de Educaciв”ңв”Ӯn del Gobierno de Aragв”ңв”Ӯn entre 2011 y 2015 y miembro del Partido Popular. El dato es vox pв”ңв”Ӯpuli porque las manifestaciones ciudadanas recorrв”ңВЎan obligadas otros itinerarios para no molestarla; ademв”ңГӯs de que allв”ңВЎ mismo el profesor Antonio Aramayona se colocaba a protestar diariamente desde junio de 2013 por la polв”ңВЎtica de Educaciв”ңв”Ӯn de la DGA.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65505700, -0.88009600, '0101000020E6100000B0E42A16BF29ECBF080264E8D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14760231379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14760231379.webp', 'https://www.flickr.com/photos/zaragozaantigua/14760231379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21881, 'Calle de Alfonso I 1931', 'Imagen capturada en la calle de Alfonso I en el punto donde desde la izquierda desemboca la calle de la Manifestaciв”ңв”Ӯn, y donde hacia la derecha comienza la calle de Espoz y Mina. Hacia el fondo, manzanas finales del tramo hasta la plaza del Pilar, que al fondo presenta su antigua y despejada fachada, mв”ңГӯs visible por la realizaciв”ңв”Ӯn de la foto en в”ңВ®poca invernal, como ilustran los в”ңГӯrboles de la plaza. Entre los bajos comerciales entoldados a la izquierda, la tienda de tejidos de Pascual Blasco D''Harcourt. En la umbrв”ңВЎa derecha, guanterв”ңВЎa La Catalana.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65545500, -0.87982800, '0101000020E6100000E25CC30C8D27ECBFF67F0EF3E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47569597722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47569597722.webp', 'https://www.flickr.com/photos/zaragozaantigua/47569597722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21987, 'Calle de Alfonso I 1949', 'Acuarela incluida en la serie "Rincones de Espaв”ңв–’a", publicada en 1953 por los laboratorios Roche de Madrid, que reproduce la calle de Alfonso I, con el Pilar al fondo. Fuente: www.delcampe.net', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65517900, -0.88009900, '0101000020E6100000F4C0C760C529ECBF5303CDE7DCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30241943843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30241943843.webp', 'https://www.flickr.com/photos/zaragozaantigua/30241943843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22392, 'Calle Olmo 1965', 'Calle del Olmo. Al fondo, la calle del Temple. Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65553400, -0.88188900, '0101000020E6100000F777B6476F38ECBF42B5C189E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22750235347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22750235347.webp', 'https://www.flickr.com/photos/zaragozaantigua/22750235347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23287, 'Calle de Alfonso I 1909', 'Imagen de la calle Alfonso I enfocando en direcciв”ңв”Ӯn hacia el Coso Alto. La calle de la izquierda es la de Espoz y Mina. La de la derecha, Manifestaciв”ңв”Ӯn. Al fondo, fachada del palacio del marquв”ңВ®s de Campo Franco, que pocos aв”ңв–’os despuв”ңВ®s serв”ңГӯ piqueteado para dar paso al edificio del Banco de Aragв”ңв”Ӯn, obra de Manuel del Busto (1913). Fuente: Instituto Amatller de Arte Hispв”ңГӯnico (Arxiu Mas).', 1909, 1909, 1909, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65555100, -0.87971000, '0101000020E610000066DAFE959526ECBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15700543099.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15700543099.webp', 'https://www.flickr.com/photos/zaragozaantigua/15700543099/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23291, 'Calle de Alfonso I 1908', 'Vista de la calle de Alfonso I, desde el cruce con las calles Contamina (izquierda), y Goya (derecha). Antes de la instalaciв”ңв”Ӯn del local comercial "La Casa Blanca".', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65545300, -0.87984000, '0101000020E6100000F2CD3637A627ECBF558847E2E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20364430090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20364430090.webp', 'https://www.flickr.com/photos/zaragozaantigua/20364430090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23295, 'Calle Manifestaciв”ңв”Ӯn c.1895', 'Luminosa imagen finisecular capturada desde el primer piso del 82 de la calle Manifestaciв”ңв”Ӯn (actual 40), hacia el punto de cruce entre esta calle, y la de Alfonso I, por donde transita hacia la plaza del Pilar una humana procesionaria. En los bajos del 89-91 (actual 35), el "Comercio de Valero Palomar". Al otro lado de la calle Alfonso I, arranca hacia la izquierda el callejв”ңв”Ӯn de la Leche, y hacia la derecha los primeros edificios impares de la calle Espoz y Mina, que no es que parezca estrecharse: es que lo hace. En los aв”ңв–’os 20 del siglo XX, la Leche serв”ңГӯ redenominada "Fray Juan Cebriв”ңГӯn". Fuente: donaciв”ңв”Ӯn de Luis Gв”ңв”Ӯmez Laguna, Archivo Pв”ңв•‘blico Municipal.', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65545300, -0.87984000, '0101000020E6100000F2CD3637A627ECBF558847E2E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622105418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622105418.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622105418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23299, 'Calle de Alfonso I c.1910', 'En 1908, el ayerbense Celestino Salinero Ena visitв”ңв”Ӯ la ciudad de Parв”ңВЎs, y quedв”ңв”Ӯ impresionado por el comercio denominado "La Maison Blanche", especializado en la venta de ropa "blanca". A la vuelta, mientras Zaragoza celebraba el Centenario I de los "Sitios", Celestino se embarcв”ңв”Ӯ en la aventura de reproducir en la ciudad lo visto en Parв”ңВЎs. Asв”ңВЎ, en la calle Alfonso I nв”¬в•‘ 22 (local y primera planta), junto a la entrada de la calle Goya, fundв”ңв”Ӯ "La Casa Blanca", unos innovadores y exitosos "grandes" talleres de confecciв”ңв”Ӯn y venta directa de gв”ңВ®neros de punto, juegos de cama, cubierta, toallas, mantelerв”ңВЎas... De la ciudad de la luz se trajo, tambiв”ңВ®n, la francesa idea de iluminar el comercio con lв”ңГӯmparas de gas, siendo pionero en Zaragoza. En la imagen, Celestino Salinero Ena posando ante su empresa vital. Fuente visual: aportaciв”ңв”Ӯn de Mariano Lacruz Pв”ңВ®rez de una reproducciв”ңв”Ӯn fotogrв”ңГӯfica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marв”ңВЎa Josв”ңВ® Salinero (nieta de Celestino Salinero).', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23242807685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23242807685.webp', 'https://www.flickr.com/photos/zaragozaantigua/23242807685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23315, 'Calle de Alfonso I 1908', 'Imagen capturada en la calle de Alfonso I durante la visita del rey Alfonso XIII el dв”ңВЎa 15 de junio de ese aв”ңв–’o a diversos eventos relacionados con el primer centenario del asedio francв”ңВ®s de 1808. En este caso se trata de la "procesiв”ңв”Ӯn cв”ңВЎvico-religiosa" que acompaв”ңв–’aba los fв”ңВ®retros de las heroв”ңВЎnas Casta в”ңГјlvarez, Manuela Sancho y Agustina Zaragoza desde el templo del Pilar y hasta la iglesia del Portillo, donde fueron inhumadas. La instantв”ңГӯnea, realizada a la altura del nв”¬в•‘ 28 de la calle, junto al emboque a la calle de Espoz y Mina donde destaca al fondo el depв”ңв”Ӯsito de transparentes de "La Veneciana", recoge el paso del cortejo en torno al rey Alfonso XIII flanqueado por los infantes Luis Alfonso y Luis Fernando, precedido por el marquв”ңВ®s de Viana y seguido por los ministros del gobierno (Gracia y Justicia y Guerra), ademв”ңГӯs de varios otros marqueses, generales y condes. Las crв”ңв”Ӯnicas informan que antes de la procesiв”ңв”Ӯn las nubes descargaron una fuerte tormenta que con naturalidad convirtiв”ңв”Ӯ las terrosas calles del recorrido, como es el caso de la de Alfonso I, en simpв”ңГӯticos barrizales.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65540700, -0.87993600, '0101000020E61000007A56D28A6F28ECBFE4486760E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52079851856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52079851856.webp', 'https://www.flickr.com/photos/zaragozaantigua/52079851856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24245, 'Calle de Alfonso I 1947', 'Imagen capturada en la calle Alfonso I, a la altura del nв”¬в•‘ 28, frente al callejв”ңв”Ӯn de las Once Esquinas, donde tenв”ңВЎa su estudio el "pintor-fotв”ңв”Ӯgrafo" navarro в”ңГјngel Hilario Garcв”ңВЎa de Jalв”ңв”Ӯn, cuya denominaciв”ңв”Ӯn artв”ңВЎstica era la que figura en el cartel anunciador: Jalв”ңв”Ӯn в”ңГјngel. Aparcado tranquilamente en la calle, un Peugeot 202, y delante, posado de tres elegantes seв”ңв–’oras. Fuente visual: www.todocoleccion.net/', 1947, 1947, 1947, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65523200, -0.87996700, '0101000020E61000003BE5D18DB028ECBF76A565A4DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30638539700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30638539700.webp', 'https://www.flickr.com/photos/zaragozaantigua/30638539700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24400, 'San Cayetano 1899', 'Desde las alturas del antiguo palacio de Guara, en la calle de la Montera, un vistazo en direcciв”ңв”Ӯn noroeste muestra los tejados del barrio de San Felipe, y la cв”ңв•‘pula y torrecillas de la iglesia de Santa Isabel de Portugal, o de San Cayetano, denominaciв”ңв”Ӯn que en la в”ңВ®poca de la imagen (y parece ser que todavв”ңВЎa) era considerada "vulgar" o asв”ңВЎ llamada por el "vulgo", si bien era esa la histв”ңв”Ӯrica denominaciв”ңв”Ӯn de la casa, convento e iglesia de los padres clв”ңВ®rigos regulares de la providencia, o religiosos teatinos, sus regentes. Fuente visual: Francisco Gв”ңв”Ӯrriz, Archivo Municipal de Zaragoza', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65553400, -0.88188900, '0101000020E6100000F777B6476F38ECBF42B5C189E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28406008944.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28406008944.webp', 'https://www.flickr.com/photos/zaragozaantigua/28406008944/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24479, 'Imprenta Berdejo Casaв”ңв–’al 1925', 'Taller de la "Imprenta de Arte Berdejo Casaв”ңв–’al", en su ubicaciв”ңв”Ӯn de la calle Loscos 7 (antigua Jazmв”ңВЎn). La captura se ha realizado con motivo de la tirada en prensa del nв”ңв•‘mero 1 de la revista "Aragв”ңв”Ӯn", в”ңв”Ӯrgano de expresiв”ңв”Ӯn del "Sindicato de Iniciativa y Propaganda de Aragв”ңв”Ӯn" (SIPA). En el colectivo posado, junto al personal del taller, el secretario del SIPA, Eduardo Cativiela y Pв”ңВ®rez, que sostiene un ejemplar de la revista. y junto a в”ңВ®l, Eduardo Berdejo Casaв”ңв–’al, editor de la revista, y propietario de la imprenta. Fuente: Foto Larraz, amablemente proporcionada por Mariano Lacruz Pв”ңВ®rez.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65556900, -0.88063200, '0101000020E61000004DF4F928232EECBFBEA25BAFE9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22528904220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22528904220.webp', 'https://www.flickr.com/photos/zaragozaantigua/22528904220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25070, 'Camarada Fleta 1936', 'в”ңГјngel Jalв”ңв”Ӯn (в”ңГјngel Hilario Garcв”ңВЎa de Jalв”ңв”Ӯn Hueto), Diputaciв”ңв”Ӯn de Zaragoza, agosto 1936. Retrato de Miguel Burro Fleta. Imagen del tenor Fleta habilitado con el uniforme de la Falange Espaв”ңв–’ola de las JONS (Juntas de Ofensiva Nacional-Sindicalista), capturado de tal traza en el Estudio fotogrв”ңГӯfico de в”ңГјngel Jalв”ңв”Ӯn (Alfonso I, 28) cuando ya no habв”ңВЎa rojos en la costa. Falleciв”ңв”Ӯ apenas dos aв”ңв–’os despuв”ңВ®s, y en su homenaje, la nueva, leal y digital corporaciв”ңв”Ӯn municipal cambiв”ңв”Ӯ de nombre a la calle Fletas, por "Avenida del Tenor Fleta". Fuente: web.dpz.es/arscatalogi.es/foto.asp?index=2851', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65497800, -0.88015400, '0101000020E6100000D731AEB8382AECBFBCCCB051D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15696653438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15696653438.webp', 'https://www.flickr.com/photos/zaragozaantigua/15696653438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25895, 'Calle del Olmo, c. 1968', 'Pintura centrada en el cruce de las calles del Olmo, desde donde el autor ha capturado la escena, y del Temple, donde al fondo destaca la portalada de acceso al nв”ңв•‘mero 14 de esa calle, una vivienda posiblemente del siglo XVII construida sobre el solar de una parte del gran complejo monв”ңГӯstico de la Orden del Temple que ocupв”ңв”Ӯ toda esa manzana.y que da nombre a esa calle. A la derecha, vista parcial del antiguo inmueble del nв”¬в•‘ 11 de la calle del Temple, posteriormente derribado junto con sus vecinas de los nв”ңв•‘meros 13 y 15 y que a finales de los aв”ңв–’os 80 del pasado siglo XX su solar conformв”ңв”Ӯ un singular espacio poblado de bancos de sentarse y arbolitos, un antecedente al desarrollo, veinte aв”ңв–’os despuв”ңВ®s, del proyecto "Estonoesunsolar" y que desde principios de este siglo XXI fue objeto de un desarrollo edilicio que conformв”ңв”Ӯ el moderno inmueble del actual nв”¬в•‘ 18 de la calle del Olmo.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65553500, -0.88191000, '0101000020E6100000D47D00529B38ECBF12312592E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53205391874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53205391874.webp', 'https://www.flickr.com/photos/zaragozaantigua/53205391874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20887, 'Fundaciв”ңв”Ӯn de Caesaraugusta', 'Emilio Gil Murillo, "Origen y fundaciв”ңв”Ӯn de Zaragoza ", 1896. Ayuntamiento de Zaragoza. La imagen representa idealizado el rito romano de fundaciв”ңв”Ӯn de la ciudad, en el 14 antes de la Era. Antes de iniciarlo, el augur consultв”ңв”Ӯ los auspicios para asegurarse, mediante signos visibles, de que los dioses no se oponв”ңВЎan al establecimiento de la ciudad en el lugar escogido. Los dioses no dijeron ni pв”ңВЎo. Entonces, revestido con una toga dispuesta a la antigua usanza, cogiв”ңв”Ӯ las estevas de un arado de bronce, tirado por una ternera y un toro, y trazв”ңв”Ӯ un surco alrededor de la futura urbe, siguiendo la misma lв”ңВЎnea a lo largo de la cual habrв”ңВЎa de levantarse el muro delimitador. En el transcurso de la ceremonia, se procuraba que toda la tierra levantada por la reja cayese al interior del recinto. Tras в”ңВ®l, los asistentes recogв”ңВЎan los terrones que a veces saltaban fuera del perв”ңВЎmetro y los volvв”ңВЎan a echar donde el rito establecв”ңВЎa. Al llegar al sitio previsto para las 4 puertas principales, se levantaba el arado con el fin de dejar un espacio libre de toda consagraciв”ңв”Ӯn. Cuando el oficiante alcanzв”ңв”Ӯ el punto de partida, la ciudad quedв”ңв”Ӯ virtualmente fundada.', NULL, NULL, NULL, NULL, 'CASCO HISTв”ңГҙRICO', 41.65210400, -0.87346600, '0101000020E6100000BB5F05F86EF3EBBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14753929599.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14753929599.webp', 'https://www.flickr.com/photos/zaragozaantigua/14753929599/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20892, 'Domus Calle Heroв”ңВЎsmo siglo I', 'En 1991 se documentв”ңв”Ӯ, en el solar de la calle Heroв”ңВЎsmo 5 y 7 con Aв”ңв–’в”ңв”Ӯn (en la imagen, a la derecha) de Zaragoza, una domus romana del siglo I, extramuros de la colonia. Fuente: Zaragoza. Prehistoria y arqueologв”ңВЎa, Ayuntamiento de Zaragoza, 1991.', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65117300, -0.87349900, '0101000020E6100000AAD6C22CB4F3EBBFE48409A359D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18564315843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18564315843.webp', 'https://www.flickr.com/photos/zaragozaantigua/18564315843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20893, 'в”ңГјnforas ca. 20', 'Campo de в”ңГӯnforas romano, enterradas hacia el aв”ңв–’o 20 despuв”ңВ®s de la Era, como drenaje o cв”ңГӯmara de aire para evitar humedades en las casas procedentes de las crecidas del rв”ңВЎo Ebro. En mayo de 2003 se descubriв”ңв”Ӯ este conjunto de casi un millar de в”ңГӯnforas puestas hacia abajo, en el solar de la plaza de las Tenerв”ңВЎas 9 de Zaragoza. Fuente visual: www.facebook.com/photo.php?fbid=1234779646549079&set=...', NULL, NULL, NULL, NULL, 'CASCO HISTв”ңГҙRICO', 41.65292800, -0.87130000, '0101000020E61000005227A089B0E1EBBF44520B2593D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19386927608.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19386927608.webp', 'https://www.flickr.com/photos/zaragozaantigua/19386927608/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20896, 'Plaza Asso 1991', 'Tareas de recuperaciв”ңв”Ӯn de un tramo de cloaca romana, descubierta en 1990 en la plaza Asso de Zaragoza. Al fondo, la calle Martв”ңВЎn Carrillo y la torre de la iglesia de la Magdalena. Fuente: Zaragoza. Prehistoria y arqueologв”ңВЎa, Ayuntamiento de Zaragoza, 1991.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65308900, -0.87399300, '0101000020E61000008CDAFD2AC0F7EBBF4D309C6B98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23648332264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23648332264.webp', 'https://www.flickr.com/photos/zaragozaantigua/23648332264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20898, 'Plaza Magdalena 1990', 'En 1990 se hallв”ңв”Ӯ un tramo de losas de la calzada romana del Decumano Mв”ңГӯximo, que sirviв”ңв”Ӯ para confirmar que la calle Mayor se hallaba sobre в”ңВ®ste. En la foto, el comienzo de la calle Mayor, a la altura de la plaza de la Magdalena, con la iglesia homв”ңв”Ӯnima arriba a la izquierda. Fuente: Las cloacas de Cesaraugusta, IFC, 2013.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65223900, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24194356511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24194356511.webp', 'https://www.flickr.com/photos/zaragozaantigua/24194356511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20922, 'Colegio del Padre Eterno 1778', 'Plano del terreno de las Escuelas Pв”ңв•‘blicas y del Colegio del Padre Eterno, Joseph Arberuela, Zaragoza, 19 de diciembre de 1778. El colegio del Padre Eterno, de los jesuitas, albergв”ңв”Ӯ desde 1788 las primeras instalaciones del Seminario Conciliar de San Valero y San Braulio. Se encontraba en el actual Coso 127, esquina con la calle de San Lorenzo. Fuente: Archivo General de Simancas, Ministerio de Cultura de Espaв”ңв–’a.', 1778, 1778, 1778, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65158800, -0.87402800, '0101000020E6100000A839799109F8EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20225243629.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20225243629.webp', 'https://www.flickr.com/photos/zaragozaantigua/20225243629/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20941, 'Convento de San Agustв”ңВЎn 1563', 'El convento de San Agustв”ңВЎn tal y como aparece en la vista de Zaragoza realizada en 1663 por el dibujante Anton van der Wyngaerde/Antonio de las Viв”ңв–’as.', 1563, 1563, 1563, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65140000, -0.87079400, '0101000020E61000005FB2F1608BDDEBBFA54E401361D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387299485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387299485.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387299485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20956, 'Coso Bajo 1808', '"Ruinas del Seminario vistas por la noche: cuando los patriotas, que no podв”ңВЎan asistir a la defensa de las puertas, a la luz de sus linternas y de los incendios, causados por las bombas, buscaban entre los escombros a los muertos para darles sepultura". Serie Ruinas de Zaragoza, de Juan Gв”ңГӯlvez (dibujo) y Fernando Brambila (grabado), Cв”ңГӯdiz, 1812. El conjunto de edificios del Seminario Mayor de Zaragoza se extendв”ңВЎa por el Coso Bajo en direcciв”ңв”Ӯn al Ebro, mв”ңГӯs allв”ңГӯ de la calle de San Jorge. En la acera de la gran mole semiderruida, mв”ңГӯs al fondo, se ve la entrada a la plaza de la Magdalena. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65158800, -0.87402800, '0101000020E6100000A839799109F8EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15267099411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15267099411.webp', 'https://www.flickr.com/photos/zaragozaantigua/15267099411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20967, 'Universidad 1814', '"La Academia de Zaragoza al regreso de Fernando VII". Medalla realizada por Antonio Martв”ңВЎnez y acuв”ңв–’ada por la Universidad de Zaragoza cuando se reanudaron las clases tras la retirada de los franceses en 1814. En 1913 se terminв”ңв”Ӯ una reforma que modificв”ңв”Ӯ su aspecto, a cargo de Ricardo Magdalena. Al fondo a la derecha, personificaciв”ңв”Ӯn del rв”ңВЎo Ebro. Fuente: Museo del Prado.', 1814, 1814, 1814, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65222400, -0.87323600, '0101000020E61000004D13B69F8CF1EBBF49D576137CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18985824170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18985824170.webp', 'https://www.flickr.com/photos/zaragozaantigua/18985824170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22670, 'Feria de Muestras 1976', 'Imagen en altura de la Feria de Muestras, y su caracterв”ңВЎstico mirador acristalado, desde un punto de vista contrario a la inmensa mayorв”ңВЎa de las capturas realizadas de la zona: hacia el noreste, mirando hacia la ciudad. Este pequeв”ңв–’o detalle permite observar el agujero, a la derecha, donde antes estuvieron los talleres de la Editorial Luis Vives, y ahora se estaba gestando la macizada y compacta manzana de bloques habitacionales que la iba a sustituir. Eso permite, excepcionalmente, visual directa de la calle Luis Vives y el desemboque a ella de Andrв”ңВ®s Piquer, Teresa de Jesв”ңв•‘s, y Mariano Supervв”ңВЎa, con el Grupo "Francisco Caballero" y restos supervivientes de antiguos hotelitos de la zona del Ensanche de Miralbueno, al poco derribados y sustituidos por cosas mв”ңГӯs modernas y apropiadas. Fuente visual: Gerardo Sancho Ramo (Archivo Pв”ңв•‘blico Municipal).', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63744800, -0.89883900, '0101000020E6100000ABD1AB014AC3ECBF477364E597D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23539505284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23539505284.webp', 'https://www.flickr.com/photos/zaragozaantigua/23539505284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21009, 'Arco de Valencia 1867', 'Imagen del antiguo arco de Valencia poco antes de su derribo realizado entre el 20 de enero y el 15 de febrero de ese aв”ңв–’o, al objeto de despejar las casas de los nв”ңв•‘meros 71, 73, 75 y 77 del Coso (a la derecha) que afeaban el ingreso a la Universidad Literaria, y parte de la casa del nв”¬в•‘ 96 de la calle Mayor (a la izquierda). El derribo del arco se hizo hilada a hilada de piedra, y el de las casas piso a piso, sin permitirse "derribos en grandes masas". Tal vez por ello llamaron la atenciв”ңв”Ӯn buen nв”ңв•‘mero de piedras que lucв”ңВЎan caracteres latinos, algunas de las cuales sobrevivieron al reaprovechamiento de los materiales del derribo, que aunque se realizв”ңв”Ӯ dentro de los lв”ңВЎmites de tiempo establecidos, dejв”ңв”Ӯ durante varios meses un "rastro" de grandes piedras "y no menores excabaciones" o cisternas ante la despejada fachada de la Universidad Literaria. La captura de esta fotografв”ңВЎa se ha realizado desde el arranque de la vecina calle de Palomar. En primer tв”ңВ®rmino, tramo del Coso que hasta ese momento era denominado "plaza de la Magdalena", caracterizado por las botigas comerciales y puestos ambulantes allв”ңВЎ establecidos. Al fondo, tras el arco, vista de la barroca portada de la iglesia parroquial de Santa Marв”ңВЎa Magdalena, cuya torre despunta a la izquierda. Tras el derribo del arco y las casas, una nueva plaza de la Magdalena surgiв”ңв”Ӯ entonces en su actual ubicaciв”ңв”Ӯn.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65210700, -0.87336500, '0101000020E6100000C2120F289BF2EBBF103FFF3D78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092142102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092142102.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092142102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21010, 'Puerta de Valencia 1867', 'Puerta de Valencia vista desde la puerta de la iglesia de la Magdalena, justo antes de ser demolida ese aв”ңв–’o, para dar a la plaza de la Magdalena algo mв”ңГӯs de desahogo y dejar al descubierto el frontispicio de la Universidad. Al fondo, el Coso bajo y la calle de Palomar. Fuente visual: Santos в”ңГјlvarez y Serra, en AMZ.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093846679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093846679.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093846679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21097, 'Paraninfo de la Universidad 1880', 'Sesiв”ңв”Ӯn inaugural del Congreso Filoxв”ңВ®rico celebrado en 1880 en el paraninfo de la Universidad de Zaragoza en la plaza de la Magdalena. No confundir con el actual edificio sito en la plaza de Paraв”ңВЎso, construido posteriormente. La plaga vitivinв”ңВЎcola de la filoxera fue detectada en Francia en 1865. Las 952.000 Ha de viв”ңв–’edo que tenв”ңВЎa en cultivo la provincia de Zaragoza quedaron reducidas, tras la plaga, a 12.275. El congreso cuya inauguraciв”ңв”Ӯn reproduce el croquis se celebrв”ңв”Ӯ para intentar frenar la catв”ңГӯstrofe agrв”ңВЎcola que se preveв”ңВЎa. El dibujo, de Bernardo Rico y Ortega, basado en un croquis apuntado por "D. Lascun", posiblemente Dionisio Lasuв”ңВ®n. Fuente visual: "La Ilustraciв”ңв”Ӯn Espaв”ңв–’ola y Americana".', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65221400, -0.87327900, '0101000020E61000001F1329CDE6F1EBBF26FF93BF7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856449014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856449014.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856449014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21111, 'Pl. de la Magdalena 1889', '"Saragosse. в”ңГ«glise de la Magdeleine". Fuente: J. Lв”ңВ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragв”ңв”Ӯn, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22736718751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22736718751.webp', 'https://www.flickr.com/photos/zaragozaantigua/22736718751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21135, 'Plaza de la Magdalena c.1880', 'Luminosa imagen capturada desde la altura del inmueble del nв”¬в•‘ 188 del Coso Bajo y centrada en la plaza de la Magdalena, donde destaca la torre y la puerta de ingreso a la iglesia parroquial de Santa Marв”ңВЎa Magdalena. A la izquierda, desemboque de la calle Mayor en la plaza con vista de las в”ңв•‘ltimas casas del lado de los pares tras la calle de Pelegrin. A la derecha, esquina del final de la calle de Martв”ңВЎn Carrillo con el arranque de la calle de la Universidad, donde destaca la antigua Casa Tejada, en cuyos bajos se abre la puerta de un comercio de ultramarinos donde tambiв”ңВ®n se despachaba carbв”ңв”Ӯn de haya. A continuaciв”ңв”Ӯn, leve vista de la fachada de la Universidad Literaria. Como el cielo de la fotografв”ңВЎa ha sido "editado" en origen, ha desaparecido la vista de la inacabada torre de Santiago y de la cв”ңв•‘pula central del templo del Pilar, que deberв”ңВЎan despuntar sobre Casa Tejada, asв”ңВЎ como la torre de la Seo. Hemos volteado horizontalmente la fotografв”ңВЎa tal y como aparece en el AHPZ, para darle sentido y sensibilidad.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65224000, -0.87350900, '0101000020E61000008D5F7825C9F3EBBF4F92AE997CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52230624372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52230624372.webp', 'https://www.flickr.com/photos/zaragozaantigua/52230624372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21145, 'Cuartel de Caballos Sementales 1899', 'в”ңГјlbum del Ministerio de la Guerra. Ministerio de Defensa de Espaв”ңв–’a. 1899. Por Real orden de 17 de agosto de 1885 se creв”ңв”Ӯ en Zaragoza una secciв”ңв”Ӯn de sementales al objeto de la mejora de la cabaв”ңв–’a de Aragв”ңв”Ӯn, con 85 sementales percherones y boloв”ңв–’eses. El 22 de marzo de 1905 se crea el Quinto Depв”ңв”Ӯsito de Caballos Sementales. Su ubicaciв”ңв”Ӯn, terrenos municipales de la Calle del Asalto. Allв”ңВЎ estuvieron hasta el 18 de julio de 1989. En la imagen, carruaje con tres sementales ante la puerta del Depв”ңв”Ӯsito. Detrв”ңГӯs del muro, al fondo, la calle Asalto y su confluencia con Alonso V.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65126900, -0.86970100, '0101000020E6100000478D093197D4EBBF06F357C85CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14991847139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14991847139.webp', 'https://www.flickr.com/photos/zaragozaantigua/14991847139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21157, 'Calle de la Universidad 1898', 'Instituto Universitario Provincial de Zaragoza, 1898. En 1847 se separaron las docencias de los institutos y las universidades, creв”ңГӯndose este centro en el edificio de la Universidad Literaria de La Magdalena. Su entrada estaba en la calle Universidad. En 1933 fue trasladado al edificio del suprimido Colegio del Salvador, y se le dio el nombre de "Instituto Nacional de Segunda Enseв”ңв–’anza Goya". Despuв”ңВ®s del 18 de julio de 1936, fue trasladado a la Escuela de Artes, primero, y luego regresв”ңв”Ӯ a la Magdalena. Cuando se inaugurв”ңв”Ӯ el edificio del nuevo Instituto "Goya" junto al Huerva y la avenida Goya, se trasladв”ңв”Ӯ allв”ңВЎ definitivamente en 1959. Fuente visual: www.facebook.com/photo.php?fbid=10204723386338133&set...', 1898, 1898, 1898, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65304800, -0.87297400, '0101000020E61000000744882B67EFEBBFEE5BAD1397D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19510424782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19510424782.webp', 'https://www.flickr.com/photos/zaragozaantigua/19510424782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21162, 'Calle Mayor 1893', '"Fragmento de la torre e iglesia de Santa Magdalena". Este dibujo, basado en una fotografв”ңВЎa, captura en altura la torre y parcialmente la iglesia con la calle Mayor a sus pies, estrecha como originalmente era. Por una de esas casualidades ocasionales, el dibujante se ha centrado en la fв”ңГӯbrica de la torre tal y como fue trabajada por los alarifes medievales que la levantaron, y ha prescindido del remate barroco aв”ңв–’adido posteriormente. Fuente: "La Ilustraciв”ңв”Ӯn Ibв”ңВ®rica", Barcelona.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20497312783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20497312783.webp', 'https://www.flickr.com/photos/zaragozaantigua/20497312783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21205, 'Cuartel de San Agustв”ңВЎn 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 8, Zaragoza 1908 - Centenario de los Sitios", 1907. "El convento de San Agustв”ңВЎn, donde hoy se encuentran las Factorв”ңВЎas militares, hв”ңГӯllase situado en las afueras, en un punto muy apetecido por los franceses cuando intentaron entrar en Zaragoza por la plaza de la Magdalena; durante el segundo sitio, el uno de febrero, se apoderaron de в”ңВ®l las tropas de Napoleв”ңв”Ӯn." Puerta de entrada al cuartel de San Agustв”ңВЎn, antes convento. Lo que parece un guardia espera sentado tranquilo. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65071100, -0.87039700, '0101000020E61000001B2B31CF4ADAEBBFE012807F4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750296987.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750296987.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750296987/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21246, 'Pl. de la Magdalena 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 27, Zaragoza 1908 - Centenario de los Sitios", 1907. "Uno de los edificios mв”ңГӯs antiguos de Zaragoza; muy castigado por hallarse detrв”ңГӯs de la puerta de Valencia, frente a la cual los franceses colocaron el 7 de febrero de 1809, un caв”ңв–’в”ңв”Ӯn de a 24, con el que abrieron una gran brecha. En sus cisternas fueron sepultadas numerosas vв”ңВЎctimas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20150686613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20150686613.webp', 'https://www.flickr.com/photos/zaragozaantigua/20150686613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21247, 'Ruinas del Hospitalito 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 29, Zaragoza 1908 - Centenario de los Sitios", 1907. "Efecto de las bombas enemigas en la capilla de este benв”ңВ®fico establecimiento conocido con el nombre de Hospitalito de la Magdalena. Despuв”ңВ®s de la explosiв”ңв”Ӯn del almacв”ңВ®n de la pв”ңв”Ӯlvora (27junio), en el Hospitalito fueron custodiados los enseres de las casas arruinadas, y en su cementerio enterrв”ңГӯronse las vв”ңВЎctimas." El Hospitalito u "Hospitalico de Nuestra Seв”ңв–’ora de la Misericordia u Hospital de Niв”ңв–’os y Niв”ңв–’as Huв”ңВ®rfanos de la ciudad de Zaragoza" fue fundado en 1543 y arruinado en 1808. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65172600, -0.87326300, '0101000020E6100000B3D1393FC5F1EBBFF8F9EFC16BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20150826383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20150826383.webp', 'https://www.flickr.com/photos/zaragozaantigua/20150826383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21256, 'Calle Heroв”ңВЎsmo 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 22, Zaragoza 1908 - Centenario de los Sitios", 1907. "En esta calle, que viene a salir al Coso en las inmediaciones de la plaza de la Magdalena, riв”ңв–’в”ңВ®ronse luchas formidables, cuerpo a cuerpo, entre sitiadores y sitiados. Minв”ңГӯronse las casas, que fueron asaltadas una a una, y reconquistadas igualmente a cuenta de sangre y vidas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65085200, -0.87403600, '0101000020E61000005EDA70581AF8EBBFA2444B1E4FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20582520218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20582520218.webp', 'https://www.flickr.com/photos/zaragozaantigua/20582520218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21261, 'Calle de las Tenerв”ңВЎas 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 39, Zaragoza 1908 - Centenario de los Sitios", 1907. "Llamado asв”ңВЎ por haberse destinado alguna de sus casas a la fabricaciв”ңв”Ӯn de curtidos. En su lugar hallв”ңГӯbase antes emplazada la puerta del Sol. A este arrabal pertenecв”ңВЎa el llamado corral de Marigaita desde donde se dominaba gran parte de la ribera del Ebro, por lo cual se construyeron allв”ңВЎ muy importantes baterв”ңВЎas que riв”ңв–’eron fieras luchas." Vista de la actual calle de Alonso V en su confluencia con la plaza de las Tenerв”ңВЎas. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65316900, -0.87164300, '0101000020E6100000CA3159DC7FE4EBBF69E1B20A9BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20763354052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20763354052.webp', 'https://www.flickr.com/photos/zaragozaantigua/20763354052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21262, 'Calle del Pozo 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 2, Zaragoza 1908 - Centenario de los Sitios", 1907. "Por el buen punto de vista que ofrecв”ңВЎa esta casa, cuya entrada estв”ңГӯ por la calle de Palomar, las balas enemigas hicieron blanco en ella frecuentemente. Durante el segundo sitio los franceses intentaron penetrar en Zaragoza por este punto pero, sin pasar de la plaza de la Magdalena, siempre fueron enв”ңВ®rgicamente rechazados." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65125200, -0.87232000, '0101000020E6100000EEB1F4A10BEAEBBF30BABC395CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20767321535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20767321535.webp', 'https://www.flickr.com/photos/zaragozaantigua/20767321535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21380, 'Coso Bajo c.1910', 'Anselmo Marв”ңВЎa Coyne, Diputaciв”ңв”Ӯn de Zaragoza, ca. 1910 Imagen de tremenda carretada de aguateros en el Coso Bajo, a la altura de la plaza de la Magdalena. A la izquierda, la Universidad Literaria de la Magdalena, antes de su reforma por Ricardo Magdalena. Fuente: web.dpz.es/arscatalogi.es/foto.asp?index=2818', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15854328636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15854328636.webp', 'https://www.flickr.com/photos/zaragozaantigua/15854328636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21421, 'Plaza de las Tenerв”ңВЎas 1911', 'Danzantes en la plaza de las Tenerв”ңВЎas, durante las fiestas de la Virgen del Carmen. Al fondo, acceso a la plazuela de la Rebolerв”ңВЎa.', 1911, 1911, 1911, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65312700, -0.87155900, '0101000020E6100000541A31B3CFE3EBBF3A9160AA99D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31581924166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31581924166.webp', 'https://www.flickr.com/photos/zaragozaantigua/31581924166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21427, 'Instituto aв”ңв–’os 10', 'Grupo de profesores (con birrete) y demв”ңГӯs personal del Instituto General y Tв”ңВ®cnico de Zaragoza (antes Instituto Universitario Provincial), en el patio de su sede en el edificio de la Universidad Literaria, con entrada por la calle Universidad. En esa в”ңВ®poca fueron alumnos Ramв”ңв”Ӯn J. Sender y Marв”ңВЎa Moliner. El archivo del que procede la imagen se halla hoy en la sede del Instituto Goya, heredero de aquв”ңВ®l desde 1959. Fuente: Archivo IES Goya de Zaragoza.', 1910, 1910, 1919, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65265400, -0.87290000, '0101000020E610000074B515FBCBEEEBBF42CD902A8AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32973656955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32973656955.webp', 'https://www.flickr.com/photos/zaragozaantigua/32973656955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21642, 'Coso Bajo, c.1926', 'Imagen capturada desde la altura del nв”¬в•‘ 182 del tramo bajo del Coso y centrada un carro a la puerta de la tienda de comestibles de Esteban Martв”ңВЎnez. A la derecha y al fondo, entrada a la plaza de la Magdalena y vista al ingreso principal a la Universidad Literaria de Zaragoza. En primer tв”ңВ®rmino, tendido tranviario de la lв”ңВЎnea Magdalena-Mercado, antes Circunvalaciв”ңв”Ӯn.', 1926, 1926, 1926, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65197600, -0.87340200, '0101000020E61000000C5A48C0E8F2EBBF71E316F373D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51126969715.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51126969715.webp', 'https://www.flickr.com/photos/zaragozaantigua/51126969715/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21707, 'Casa Gavв”ңВЎn 1930', 'Foto Palacio. 1930. Imagen de la antigua "Casa Gavв”ңВЎn", esquinada entre la calle Palafox (derecha), y la calle Pedro Liв”ңв–’в”ңГӯn (a la izquierda). Salvada de las obras de apertura de San Vicente de Paв”ңв•‘l, por estar un poco alejada del epicentro del nuevo vial, varias dв”ңВ®cadas despuв”ңВ®s serв”ңВЎa piqueteada para construir encima una indescriptible edificaciв”ңв”Ӯn de Telefв”ңв”Ӯnica. Fuente visual: "Aragв”ңв”Ӯn : revista grв”ңГӯfica de cultura aragonesa" (Aв”ңв–’o VI, Nв”¬в•‘ 63, dic. 1930).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65360900, -0.87406300, '0101000020E6100000C498F4F752F8EBBF86AFAF75A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16012092932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16012092932.webp', 'https://www.flickr.com/photos/zaragozaantigua/16012092932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21790, 'Coso Bajo c.1934', 'Vista aв”ңВ®rea del Coso bajo y sus alrededores. Arriba a la izquierda, el gran edificio de la Universidad de la Magdalena. A la derecha, el intrincado laberinto de la calle del Sepulcro, Pallaruelo, del Lobo, Monserrate, Conde de Alperche, Chantre... Fuente visual: www.facebook.com/photo.php?fbid=575487972606230&set=g...', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24147192773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24147192773.webp', 'https://www.flickr.com/photos/zaragozaantigua/24147192773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21952, 'Calle Universidad 1949', 'Imagen de la calle Universidad capturada desde el tramo entre las calles Torrellas y Palafox, que es la primera calle que se abre a la izquierda. Al fondo, la calle Don Teobaldo, con leve vista del Convento de las Canonesas del Sto. Sepulcro. Inmediata, a la derecha, la calle Trinidad. La imagen se ha tomado justo al lado de los muros de la antigua Universidad Literaria de la Magdalena. Fuente visual: Juan Mora Insa, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65322600, -0.87285500, '0101000020E610000075CDE49B6DEEEBBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19171108130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19171108130.webp', 'https://www.flickr.com/photos/zaragozaantigua/19171108130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21990, '&quot;CEFA&quot; Plaza de Asso, 1946', 'Imagen del interior de los originales talleres de Celulosa Fabril "CEFA", empresa fundada por Eduardo Blanchard Castillo en 1946, en el nв”¬в•‘ 1 de la plaza de Asso, entre las calles del в”ңГҙrgano, y Torrellas. Allв”ңВЎ se acometв”ңВЎa la fabricaciв”ңв”Ӯn de cв”ңГӯpsulas de celulosa para tapones de botellas, y pronto comenzarв”ңВЎa la producciв”ңв”Ӯn de gelatinas, sacarinas y jabones, y en 1952, el desarrollo de la inyecciв”ңв”Ӯn de termoplв”ңГӯsticos, que hizo de los juguetes una de las grandes seв”ңв–’as de identidad de la empresa. A mediados de esa dв”ңВ®cada, este espacio se habв”ңВЎa quedado muy pequeв”ңв–’o, lo que derivв”ңв”Ӯ en su traslado a una nueva y mucho mayor planta, en la calle de Miguel Servet. Fuente visual: "CEFA: una mirada al futuro 1946-2016", en Archivo Josв”ңВ® Marв”ңВЎa Ballestв”ңВЎn Miguel.', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65294000, -0.87378700, '0101000020E61000003F70952710F6EBBF0820B58993D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30749184261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30749184261.webp', 'https://www.flickr.com/photos/zaragozaantigua/30749184261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22021, 'Calle de Josв”ңВ® Palafox c.1940', 'Imagen del в”ңв•‘ltimo tramo de la calle de Josв”ңВ® Palafox, donde destaca a la derecha, en el nв”¬в•‘ 29, el Laboratorio Quв”ңВЎmico Municipal construido en 1914 con proyecto de Josв”ңВ® de Yarza Echenique. Frente a в”ңВ®l, los antiguos inmuebles de los nв”ңв•‘meros 28 y 30. Hacia el fondo, la calle se estrecha de forma notable hasta el cruce con la de Gavв”ңВЎn. La imagen estв”ңГӯ realizada desde la esquina con la calle de la Universidad, a espaldas de la homв”ңв”Ӯnima e histв”ңв”Ӯrica instituciв”ңв”Ӯn educativa, con un tancredo en primer tв”ңВ®rmino ejerciendo de tal.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65324200, -0.87286500, '0101000020E610000058569A9482EEEBBFD32F116F9DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49898657137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49898657137.webp', 'https://www.flickr.com/photos/zaragozaantigua/49898657137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22036, 'Calle del в”ңГҙrgano c.1940', 'Grabado de Salvador Martв”ңВЎnez Blasco con una vista de la calle del в”ңГҙrgano y la iglesia de la Magdalena. A la derecha, casona de los Lanes de Villanueva, esquinera con la calle de Martв”ңВЎn Carrillo y derribada a principios de los aв”ңв–’os 40. Su piedra armera con el escudo perdura en el Museo de Zaragoza.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54413600082.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54413600082.webp', 'https://www.flickr.com/photos/zaragozaantigua/54413600082/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22110, 'Calle Mayor 1951', 'Imagen del в”ңв•‘ltimo tramo de la calle Mayor, paralelo a la iglesia parroquial de la Magdalena, casi ya en la plaza del mismo nombre. En el lateral del templo luce soleado, aв”ңв•‘n, el antiguo bajorrelieve en forma de capilla, o figurado altar, dedicada a San Cristв”ңв”Ӯbal de Licia, que ademв”ңГӯs le daba nombre al arquitrabado "arco" bajo el que embocaba, justo enfrente, la calle de San Cristв”ңв”Ӯbal, entre la "Farmacia" de la imagen (edificio luego derribado), y el abalconado nв”¬в•‘ 60 de la calle Mayor (sobrevive). Esta tipologв”ңВЎa de "arcos" era prв”ңГӯctica comв”ңв•‘n como forma de ganar espacio extra habitacional en zonas densamente edificadas de la ciudad antigua, dejando la altura suficiente para que pudiera transitar por debajo, sin problemas, una persona a lomos de caballerв”ңВЎa. Fuente visual: Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22004534908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22004534908.webp', 'https://www.flickr.com/photos/zaragozaantigua/22004534908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22141, 'Calle de Gavв”ңВЎn 1951', 'Imagen de la calle de Gavв”ңВЎn, que fuera antiguo callizo de Domingo Vero, capturada en el tramo entre la plaza de Asso, y la calle de Palafox, al fondo destaca el esquinero y superviviente palacio del siglo XVI de los Gurrea de Castro. Fuente visual: Juan Mora Insa, Archivo Municipal de Zaragoza.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65362100, -0.87391600, '0101000020E6100000B56FEEAF1EF7EBBF4A7D59DAA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25052731130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25052731130.webp', 'https://www.flickr.com/photos/zaragozaantigua/25052731130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21644, 'Fray Luis Amigв”ңв”Ӯ 1921', 'Imagen capturada en la casa-reformatorio del Buen Pastor establecida desde 1917 en Torre-Ramona, con un posado de la comunidad de religiosos Terciaros capuchinos de Nв”¬В¬ Sв”¬В¬ de la Soledad encargada de administrar esta instituciв”ңв”Ӯn. Entre los posantes destaca la figura de Fray Luis Amigв”ңв”Ӯ (nacido como Josв”ңВ® Marв”ңВЎa Amigв”ңв”Ӯ Ferrer), el segundo sentado desde la izquierda, fundador de la congregaciв”ңв”Ӯn en 1889 y obispo desde 1907, durante una visita a sus hermanos. Una derivada de su apellido hizo que popularmente se conociera a esta congregaciв”ңв”Ӯn como "amigonianos".', 1921, 1921, 1921, 'Anos 20', 'LAS FUENTES', 41.64205800, -0.86345600, '0101000020E6100000861E317A6EA1EBBF4D11E0F42ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51246815274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51246815274.webp', 'https://www.flickr.com/photos/zaragozaantigua/51246815274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22900, 'Felipe Gonzв”ңГӯlez 1983', 'Foto: EFE. Felipe Gonzв”ңГӯlez, presidente del gobierno espaв”ңв–’ol entre 1982 y 1996, inaugura la 17в”¬В¬ ediciв”ңв”Ӯn de la FIMA (Feria Internacional de Maquinaria Agrв”ңВЎcola) en la Feria de Muestras de Zaragoza. A la izquierda, Josв”ңВ® Luis Martв”ңВЎnez Candial, entonces presidente de la Cв”ңГӯmara de Comercio e Industria de Zaragoza y despuв”ңВ®s de Ibercaja. Fuente: Ayuntamiento de Valladolid.', 1983, 1983, 1983, 'Anos 80', 'UNIVERSIDAD', 41.63759000, -0.89959300, '0101000020E6100000A5BC564277C9ECBFDA20938C9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21246408275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21246408275.webp', 'https://www.flickr.com/photos/zaragozaantigua/21246408275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22177, 'Calle del Asalto 1951', 'Despejada imagen de la parte final de la calle de Asalto capturada desde el principio de la calle de Monreal, con el irregular tramo donde desembocan en ella, por la derecha, las calle de la Rebolerв”ңВЎa, y la de Alonso V. A la izquierda, olmos (posiblemente) junto a la acequia que proveв”ңВЎa de agua a los talleres y fв”ңГӯbricas textiles ubicadas en esta zona, recuerdo de cuando siglos atrв”ңГӯs esta era la "rebolerв”ңВЎa" de la ciudad, donde se trataban y curtв”ңВЎan pieles; de esta acequia se derivaba, poco despuв”ңВ®s. un riego que todavв”ңВЎa era denominado "de los Curtidores". A continuaciв”ңв”Ӯn de los в”ңГӯrboles, el ingreso al cuartel de Remonta y de Sementales del Ejв”ңВ®rcito y, al fondo, la antigua y gran torre de Juan Faustino Bruil y Olliarburu, luego de Monserrat, y que en 1965 serв”ңВЎa parque Bruil. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65197000, -0.86989200, '0101000020E61000003FAA61BF27D6EBBF8FFCC1C073D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31583846812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31583846812.webp', 'https://www.flickr.com/photos/zaragozaantigua/31583846812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22251, 'Calle de San Cristв”ңв”Ӯbal 1953', 'Pintura de la calle y el arco de San Cristв”ңв”Ӯbal, por Antonio Marв”ңВЎa Almazв”ңГӯn, 1953. Al fondo, el inicio de la calle Mayor.', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65225800, -0.87401200, '0101000020E61000003CF88903E8F7EBBFF646AD307DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54414106768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54414106768.webp', 'https://www.flickr.com/photos/zaragozaantigua/54414106768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22279, 'Universidad de la Magdalena 1968', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 05/09/1968. Derribo de la antigua Universidad de la Magdalena. Imagen tomada desde la Plaza de la Magdalena. A la derecha, el Coso Bajo. "Hay que rendirse a la evidencia, no se podв”ңВЎa evitar la demoliciв”ңв”Ӯn de un edificio como в”ңВ®ste: un caserв”ңв”Ӯn inmenso que no admitв”ңВЎa reformas satisfactorias y que, al desaparecer, darв”ңГӯ paso a modernos y eficaces edificios que albergarв”ңГӯn centros y dependencias de Enseв”ңв–’anza Media y Primaria, construidos de acuerdo con las mв”ңГӯs modernas directrices pedagв”ңв”Ӯgicas. Y el futuro gran edificio tendrв”ңГӯ desde luego una fachada de estilo mudв”ңВ®jar, que harв”ңГӯ juego con la inmediata iglesia de la Magdalena, cuya graciosa torre ha sido devuelta al mв”ңГӯs brillante momento de su prв”ңВЎstino gв”ңв”Ӯtico-mudв”ңВ®jar; con lo que la plaza que se abre ante ella puede convertirse en uno de los rincones mв”ңГӯs evocadores y bellos de Zaragoza". Г”ГҮГ¶ Ramв”ңв”Ӯn Salanova (ABC, 21.09.1968)', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65241600, -0.87349300, '0101000020E6100000211E8997A7F3EBBF8EB1135E82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14990204666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14990204666.webp', 'https://www.flickr.com/photos/zaragozaantigua/14990204666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22386, 'Calle в”ңГҙrgano 1968', 'Calle del в”ңГҙrgano. A la izquierda, iglesia de la Magdalena. Al fondo, calle Mayor. Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65261600, -0.87412200, '0101000020E610000001DA56B3CEF8EBBF556CCCEB88D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22529747333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22529747333.webp', 'https://www.flickr.com/photos/zaragozaantigua/22529747333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22387, 'Calle Martв”ңВЎn Carrillo 1968', 'Calle de Martв”ңВЎn Carrillo. A la derecha, la iglesia de la Magdalena. Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65251900, -0.87375700, '0101000020E610000095D5743DD1F5EBBF62821ABE85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22530671053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22530671053.webp', 'https://www.flickr.com/photos/zaragozaantigua/22530671053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22390, 'Pl. de la Magdalena 1968', 'Plaza de la Magdalena desde la calle Martв”ңВЎn Carrillo. A la derecha, la calle Mayor. Al fondo, el Coso Bajo. Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65227100, -0.87348900, '0101000020E6100000C64D0D349FF3EBBF8A90BA9D7DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22733787348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22733787348.webp', 'https://www.flickr.com/photos/zaragozaantigua/22733787348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22395, 'Calle Martв”ңВЎn Carrillo 1968', 'Casa Tejada, en la esquina de la calle Martв”ңВЎn Carrillo con la de la Universidad (derecha), vista desde la plaza de la Magdalena. Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65245500, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF4C8E3BA583D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22831783030.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22831783030.webp', 'https://www.flickr.com/photos/zaragozaantigua/22831783030/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22396, 'Calle Don Teobaldo 1968', 'Esquina de la calle de Don Teobaldo frente al Monasterio de la Resurrecciв”ңв”Ӯn, tambiв”ңВ®n llamado Real Monasterio de Comendadoras Canonesas de la Orden Militar y Pontificia del Santo Sepulcro. Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65362600, -0.87258700, '0101000020E6100000A6457D923BECEBBF5CE84A04AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22832693050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22832693050.webp', 'https://www.flickr.com/photos/zaragozaantigua/22832693050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22408, 'Universidad Magdalena 1968', 'Imagen capturada desde la plaza de la Magdalena durante el derribo de la antigua Universidad Literaria allв”ңВЎ ubicada. Considerada mayoritariamente un "caserв”ңв”Ӯn inmenso que no admitв”ңВЎa reformas satisfactorias", estrangulaba ademв”ңГӯs el vital trв”ңГӯfico rodado del Coso Bajo, pues cuando fue construida no se tuvo la previsiв”ңв”Ӯn de pensar en в”ңВ®l. En primer plano, montoneras de piedras y cascotes de ladrillos producto del derribo. Al frente, la "Capilla de Cerbuna", sede de la Biblioteca universitaria, mantenida en pie y declarada Monumento Histв”ңв”Ӯrico-Artв”ңВЎstico (Decreto de 13 de marzo de 1969), aunque cuatro aв”ңв–’os despuв”ңВ®s se hundirв”ңГӯ como resultado de no haber realizado ninguna obra de consolidaciв”ңв”Ӯn y/o protecciв”ңв”Ӯn efectiva del edificio que, aislado de las construcciones que le arropaban, terminв”ңв”Ӯ cayв”ңВ®ndose "solo". A la derecha, el Coso Bajo. Sic transit gloria Urbis. Fuente visual: Joaquв”ңВЎn Gil Marraco (Catв”ңГӯlogo Exposiciв”ңв”Ӯn grupo "Calle a Calle", Colegio de Arquitectos de Zaragoza, abril/mayo de 1980). Amable aportaciв”ңв”Ӯn de Josв”ңВ® Luis Cintora.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65249500, -0.87271600, '0101000020E61000001C45D61A4AEDEBBFDAE6C6F484D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24558378586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24558378586.webp', 'https://www.flickr.com/photos/zaragozaantigua/24558378586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22613, 'Capilla de Cerbuna 1973', 'Foto Monge, 1973. El domingo 6 de mayo de 1973, por la tarde, se hundiв”ңв”Ӯ la Capilla Pedro Cerbuna de la antigua Universidad de Zaragoza. Era el в”ңв•‘nico vestigio que quedaba en pie. Este monumento Histв”ңв”Ӯrico Artв”ңВЎstico dejв”ңв”Ӯ sus escombros sobre el patio del colegio anexo (Colegio nacional Nuestra Seв”ңв–’ora de La Magdalena), hoy instituto. En la imagen, tomada desde el Coso Bajo, la torre de la Magdalena a la izquierda. Fuente: Diario Amanecer, 8 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19190968590.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19190968590.webp', 'https://www.flickr.com/photos/zaragozaantigua/19190968590/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22614, 'Capilla de Cerbuna 1973', 'Foto Monge, 1973. El domingo 6 de mayo de 1973, por la tarde, se hundiв”ңв”Ӯ la Capilla Pedro Cerbuna de la antigua Universidad de Zaragoza. Era el в”ңв•‘nico vestigio que quedaba en pie. Este monumento Histв”ңв”Ӯrico Artв”ңВЎstico dejв”ңв”Ӯ sus escombros sobre el patio del colegio anexo (Colegio nacional Nuestra Seв”ңв–’ora de la Magdalena), hoy instituto. La imagen estв”ңГӯ tomada desde el Coso Bajo. Fuente: Diario Amanecer, 8 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19191178720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19191178720.webp', 'https://www.flickr.com/photos/zaragozaantigua/19191178720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22673, 'Capilla Cerbuna 1973', 'Imagen de la antigua Capilla Pedro Cerbuna de la Universidad de Zaragoza, tras su derrumbe por dejaciв”ңв”Ӯn institucional, como reflejo de la abrumadoramente mayoritaria opiniв”ңв”Ӯn de que eran meras viejas piedras que no pegaban con la moderna ciudad del momento. La imagen estв”ңГӯ capturada desde el Coso Bajo, ya desahogado de las apreturas que los muros de la vieja Universidad le suponв”ңВЎan, pues originaban unas estrecheces a la "circulaciв”ңв”Ӯn", que clamaban al cielo. Al poco tiempo, todo fue terminado de derribar, y todos, tan contentos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65249500, -0.87271600, '0101000020E61000001C45D61A4AEDEBBFDAE6C6F484D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24191131276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24191131276.webp', 'https://www.flickr.com/photos/zaragozaantigua/24191131276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22713, 'Calle de Olleta 1979', 'Imagen capturada en la calle de Jusepillo de Olleta y centrada en el tramo de los pares entre las calles de Alcober y de Luzв”ңГӯn, donde destacaba el antiguo nв”ңв•‘mero 12, un inmueble de tres alturas representativo de la arquitectura tradicional en esta zona de la ciudad. A la derecha, vista parcial del antiguo nв”¬в•‘ 10. Aв”ңв–’os mв”ңГӯs tarde, casi todos los edificios de este lado de la calle serв”ңВЎan derribados, y sobre ellos se construirв”ңВЎan modernos inmuebles, algunos ya en la segunda dв”ңВ®cada del siglo XXI. A la izquierda, el bajo y esquinero nв”¬в•‘ 10 de la calle de Luzв”ңГӯn, que perdura rehabilitado, y despuв”ңВ®s el nв”¬в•‘ 15 de la calle de Olleta, derribado luego. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65227400, -0.87181300, '0101000020E6100000E4486760E4E5EBBFFB03E5B67DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29281975518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29281975518.webp', 'https://www.flickr.com/photos/zaragozaantigua/29281975518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22781, 'Pl. de Asso 1979', 'Imagen capturada en la plaza de Ignacio Jordв”ңГӯn de Asso y centrada en la antigua casa del siglo XVI que desde el siglo XVII era de la familia La Balsa, en el siglo XVIII de los La Balsa-Campi (marquesado del Palacio) para terminar recayendo en los Asso. La importancia de este edificio, aun en un entorno donde se ubicaban otras significadas casas de infanzones y nobles, determinв”ңв”Ӯ la sucesiva denominaciв”ңв”Ӯn de este recoleto espacio urbano: plaza de La Balsa, de Campi, y de Asso. De esta casa, tras varias modificaciones e intervenciones (la mв”ңГӯs reciente aв”ңв•‘n en curso) perdura, grosso modo, la traza de la fachada principal. A la izquierda, acceso a la calle de Gavв”ңВЎn y a la derecha, a la calle de Torrellas. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65317200, -0.87391600, '0101000020E6100000B56FEEAF1EF7EBBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37748363585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37748363585.webp', 'https://www.flickr.com/photos/zaragozaantigua/37748363585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22852, 'Torre de La Magdalena c.1987', 'Vista desde el edificio de la calle Pelegrв”ңВЎn 3 de la torre mudв”ңВ®jar de la iglesia de Santa Marв”ңВЎa Magdalena de Zaragoza. Al fondo, el Pilar.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259848878.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259848878.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259848878/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22862, 'Barrio de la Magdalena 1987', 'Luis Mв”ңВЎnguez. 1987. Desde la torre de la iglesia de la Magdalena, una mirada hacia el suroeste, siguiendo la calle de las Cortesв”ңВЎas, que tras llegar a San Lorenzo, se denomina de los Estudios, hasta llegar a San Jorge y toparse con la Iglesia del Real Seminario de San Carlos Borromeo, que fue la Sinagoga mayor hasta que los jesuitas le echaron el ojo. Luego, tras cruzar el Coso, la calle Espartero conduce hasta la plaza de San Miguel, donde la antigua puerta del Duque de la Victoria, se cruza el Huerva por el puente de San Josв”ңВ®, y la bruma ya no nos deja ver mucho mв”ңГӯs, aunque al fondo sobresale la Plana de Zaragoza. A la izquierda, en primerв”ңВЎsimo plano, una rara visual aв”ңВ®rea de la plazuela de la calle San Cristв”ңв”Ӯbal, con coche aparcado, por supuesto.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15658335797.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15658335797.webp', 'https://www.flickr.com/photos/zaragozaantigua/15658335797/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22874, 'Calle Mayor 1987', 'Luis Mв”ңВЎnguez. 1987. Desde la torre de la iglesia de la Magdalena, un vistazo siguiendo el decumano mв”ңГӯximo en direcciв”ңв”Ӯn oeste, o calle Mayor hacia la avenida de Cв”ңВ®sar Augusto, donde la puerta de Toledo recordaba el cierre del perв”ңВЎmetro amurallado de la ciudad romana. Sobre un panorama de tejados y cubiertas, en primer plano, el cruce con la trinchera de San Vicente de Paв”ңв•‘l, cuya apertura en los primeros aв”ңв–’os 30 del s. XX transformв”ңв”Ӯ profundamente esta parte del Casco Histв”ңв”Ӯrico. En lв”ңВЎnea recta, mв”ңГӯs o menos, la visual llega hasta la curva del rв”ңВЎo donde se levanta el puente de la Almozara. Hacia la derecha, agrupados, los remates del Torreв”ңв”Ӯn de la Zuda, y el cimborrio y la torrecilla de San Juan de los Panetes. Hacia la izquierda, el blanco remate bulboso del chaflв”ңГӯn con Don Jaime I, de Francisco Albiв”ңв–’ana. Luego, la cв”ңв•‘pula y torres de Santa Isabel-San Cayetano. Casi al fondo, la mole habitacional de la plaza de Santo Domingo, junto a la torre de San Pablo. La mole estв”ңГӯ bastante mв”ңГӯs lejos, pero su tamaв”ңв–’o parece acercarla. A la izquierda mв”ңГӯs extrema, la reciente torre "nueva" derecha de la iglesia de Santiago.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15843975905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15843975905.webp', 'https://www.flickr.com/photos/zaragozaantigua/15843975905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21233, 'Calle de Alfonso I 1908', 'Vista desde cierta altura de la calle de Alfonso I.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65309800, -0.88208100, '0101000020E61000000589EDEE013AECBFA08A1BB798D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19415078758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19415078758.webp', 'https://www.flickr.com/photos/zaragozaantigua/19415078758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22947, 'Calle de Alonso V 1987', 'Imagen capturada en la calle de Alonso V y centrada en uno de los antiguos torreones del recinto defensivo medieval en ladrillo de la ciudad allв”ңВЎ ubicados, que desde principios del siglo XVII habв”ңВЎan sido adaptados para vivienda, al igual que los compases entre torreones. El de la imagen se corresponde con el cuarto torreв”ңв”Ӯn desde la puerta de la Portaza (luego del Sol, a la derecha, fuera de plano) y ya cercano al gran complejo del convento de San Agustв”ңВЎn. La vivienda allв”ңВЎ habilitada tenв”ңВЎa adjudicado el nв”ңв•‘mero 44 (luego 26) de la calle Alonso V, con traseras a la calle de las Arcadas. Una intervenciв”ңв”Ӯn municipal posterior supuso la restauraciв”ңв”Ӯn y rehabilitaciв”ңв”Ӯn (previo derribo de las viviendas adosadas de finales del siglo XIX) de este y otros dos torreones, ademв”ңГӯs de algunos inmediatos lienzos del tramo de muralla. Fuente visual: AMZ.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65207400, -0.87101900, '0101000020E61000005C3AE63C63DFEBBF34492C2977D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38603459816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38603459816.webp', 'https://www.flickr.com/photos/zaragozaantigua/38603459816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22955, 'Calle de Alonso V 1987', 'Imagen capturada en la calle de Alonso V y centrada en uno de los antiguos torreones del recinto defensivo medieval en ladrillo de la ciudad, que desde el siglo XVII habв”ңВЎan sido adaptados para vivienda, al igual que en los compases entre los torreones se adosaron pequeв”ңв–’as viviendas recayentes tanto a esta como a la trasera calle de las Arcadas. El de la imagen se corresponde con el cuarto torreв”ңв”Ӯn desde la puerta de la Portaza, luego del Sol, que quedaba a la derecha, fuera de plano. La vivienda allв”ңВЎ habilitada tenв”ңВЎa adjudicado el nв”ңв•‘mero 26 (antiguo 44) de la calle de Alonso V. A la derecha, el adosado inmueble del nв”¬в•‘ 24 (antiguo 42), y a la izquierda restos del antiguo inmueble del nв”¬в•‘ 46, ya cercano al gran complejo del convento de San Agustв”ңВЎn. Al fondo y a la izquierda, solana sobre las traseras del inmueble del nв”¬в•‘ 13 de la calle de Barrioverde. En el momento de tomar esta fotografв”ңВЎa se estaba procediendo a urbanizar la calle. Una intervenciв”ңв”Ӯn municipal posterior supuso la restauraciв”ңв”Ӯn y rehabilitaciв”ңв”Ӯn (previo derribo de las viviendas adosadas de finales del siglo XIX) de este y otros dos torreones, ademв”ңГӯs de algunos inmediatos lienzos del tramo de muralla medieval.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65205600, -0.87085900, '0101000020E610000026AC8DB113DEEBBF8E942D9276D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48104213632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48104213632.webp', 'https://www.flickr.com/photos/zaragozaantigua/48104213632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22959, 'Calle de Martв”ңВЎn Carrillo c.1981', 'Imagen capturada en el despejado entorno de calle de Martв”ңВЎn Carrillo con el casi irreconocible aspecto de esta zona del barrio de la Magdalena tras los derribos de algunas de las antiguas casonas que tradicionalmente la caracterizaban, como la Casa de Tejada, que se levantaba en el inmediato solar de primer tв”ңВ®rmino, y que a principios de los aв”ңв–’os 90 del pasado siglo XX verв”ңВЎa construirse aquв”ңВЎ unos apreciables inmuebles seriados que desde la plaza de Asso llegan hasta las calles de Torrellas y de la Universidad. A la izquierda, leve vista del renegrido muro de la iglesia parroquial de Santa Marв”ңВЎa Magdalena y del inmueble esquinero con la calle del в”ңГҙrgano, tambiв”ңВ®n construido sobre otra solariega casona de cuyo nombre no quiero acordarme. En el centro y hacia el fondo, irrepetible vista del inmueble del nв”¬в•‘ 21 de la calle de Don Juan de Aragв”ңв”Ӯn, recayente a la plazoleta que se abre en la confluencia con la calle de Pedro Liв”ңв–’в”ңГӯn, visible temporalmente tras el derribo de la antigua casa que desde allв”ңВЎ llegaba hasta la plaza de Ignacio Jordв”ңГӯn Asso, y desde 1983 sustituida por el actual inmueble del nв”¬в•‘ 2-4 de la calle de Pedro Liв”ңв–’в”ңГӯn. Al fondo se destaca la torre de la Seo y el remate de la torre de Santa Leonor del templo del Pilar.', 1981, 1981, 1981, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52123834300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52123834300.webp', 'https://www.flickr.com/photos/zaragozaantigua/52123834300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23022, 'Plaza de Asso 1997', 'Imagen capturada en la plaza de Ignacio Jordв”ңГӯn de Asso y centrada en el antiguo inmueble del nв”¬в•‘ 28 (antes nв”¬в•‘ 36) de la calle de Juan de Aragв”ңв”Ӯn, una casona tв”ңВЎpica del siglo XVII de un modelo seriado bastante comв”ңв•‘n en el antiguo barrio de La Seo, y que aquв”ңВЎ se muestra en muy precaria situaciв”ңв”Ӯn. Aparece flanqueada por modernos edificios de viviendas (a la derecha, el sesentero nв”¬в•‘ 4 de la vecina calle de Torrejв”ңв”Ӯn; a la izquierda, el tardochentero nв”¬в•‘ 1 de la plaza de Asso). Aв”ңв–’os despuв”ңВ®s esta casa fue derribada, perdurando todavв”ңВЎa el solar dejado. Esta imagen fue posible por el derribo, en los aв”ңв–’os setenta, de la antigua gran casa del nв”¬в•‘ 1 de la plaza de Asso que confrontaba con ella, y cuyo solar sirviв”ңв”Ӯ para ampliar notablemente la antigua y recoleta plaza.', 1997, 1997, 1997, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65298600, -0.87418500, '0101000020E61000009AEB34D252F9EBBF785F950B95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49352382846.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49352382846.webp', 'https://www.flickr.com/photos/zaragozaantigua/49352382846/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23074, 'Vista Sureste 2009', 'Foto Javier Peв”ңв–’a, diciembre 2009. Vista de Zaragoza hacia el Sureste, desde la torre de la Seo. La imagen la preside la torre de La Magdalena. Fuente: www.facebook.com/photo.php?fbid=1012283675454144&set=...', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15304358694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15304358694.webp', 'https://www.flickr.com/photos/zaragozaantigua/15304358694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23120, 'Coso Bajo 2006', 'Vista del veterano solar esquinero del Coso Bajo (nв”ңв•‘mero 164) con la calle del Doctor Palomar (izquierda). Fuente: Heraldo de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65182800, -0.87327500, '0101000020E6100000C442AD69DEF1EBBFFD4E93196FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31106504104.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31106504104.webp', 'https://www.flickr.com/photos/zaragozaantigua/31106504104/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23236, 'Casa Edad de Hierro', 'Vista general de una casa en la I Edad de Hierro (750-500 antes de nuestra Era), en la actual calle Palafox nв”¬в•‘ 26. Fuente visual: Historia de cuatro ciudades, 2001.', NULL, NULL, NULL, NULL, 'CASCO HISTв”ңГҙRICO', 41.65339000, -0.87333800, '0101000020E61000005C548B8862F2EBBF48C49448A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14969299326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14969299326.webp', 'https://www.flickr.com/photos/zaragozaantigua/14969299326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23471, 'Calle del в”ңГҙrgano c.1935', 'Imagen de la puerta de acceso al antiguo nв”¬в•‘ 3 de la calle del в”ңГҙrgano, sobre la que destaca el dieciochesco blasв”ңв”Ӯn de la familia de los Sanez (sic) de Villa Nueva (Lanes de Villanueva). Esta casona, esquinera con la calle de Carrillo (a la derecha, fuera de plano), y frente a las traseras de la iglesia parroquial de la Magdalena, fue luego derribada al principio de los aв”ңв–’os 40, y levantado sobre su solar un edificio de nueva planta. La piedra armera con el escudo perdura en el Museo de Zaragoza. Fuente visual: Archivo Josв”ңВ® Galiay, AHPZ.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65273900, -0.87398000, '0101000020E61000006475ABE7A4F7EBBF70E998F38CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31458861225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31458861225.webp', 'https://www.flickr.com/photos/zaragozaantigua/31458861225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23534, 'Universidad Magdalena 1932', 'Fotografв”ңВЎa Martв”ңВЎn Chivite. Heraldo de Aragв”ңв”Ӯn. 10-05-1932. El Debate parlamentario sobre el Estatuto de Cataluв”ңв–’a pronto se extendiв”ңв”Ӯ a un agrio debate paralelo en los periв”ңв”Ӯdicos, especialmente entre la prensa mв”ңГӯs reaccionaria. En la calle, los elementos de la derecha mв”ңГӯs extrema, provocaron graves sucesos, como este de Zaragoza que saltв”ңв”Ӯ a la prensa estatal. En la Plaza de la Magdalena, entonces sede del Rectorado y las Facultades de Derecho y de Filosofв”ңВЎa y Letras de la Universidad, estudiantes contrarios al debate del Estatuto, desempedraron adoquines del firme, los introdujeron al interior de la Universidad, y se hicieron fuertes dentro. Avisados los Guardias de Asalto, fueron exhortaron a que depusieran su actitud, a lo que respondieron lanzando adoquines, uno de los cuales impactв”ңв”Ӯ sobre un Teniente, causв”ңГӯndole heridas graves. Ademв”ңГӯs, en los altercados que siguieron, con intercambio de disparos de bala incluido, resultaron heridos un par de estudiantes, y un Cabo. La Guardia de Asalto entrв”ңв”Ӯ en el recinto, detuvo a 60 estudiantes, y cesaron los disturbios. Al lugar acudieron el Gobernador, el presidente de la Audiencia Territorial, y un juez instructor. La Junta de Gobierno de la Universidad lamentв”ңв”Ӯ lo sucedido, censurв”ңв”Ӯ el proceder de los causantes de los desв”ңв”Ӯrdenes, aplicв”ңв”Ӯ el Reglamento de disciplina escolar a los escolares menores de edad implicados, y abriв”ңв”Ӯ un expediente para depurar responsabilidades. Ademв”ңГӯs, la Universidad fue clausurada dos dв”ңВЎas. Fuente: ABC Madrid. En la imagen, publicada en prensa despuв”ңВ®s de los hechos, algunos de los estudiantes detenidos en el momento de abandonar el edificio de la Universidad de la Magdalena. Adoquines implicados, en el suelo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65208000, -0.87328900, '0101000020E6100000029CDEC5FBF1EBBF1630815B77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14666083288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14666083288.webp', 'https://www.flickr.com/photos/zaragozaantigua/14666083288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23535, 'La Magdalena 1930', '"Iglesia de Santa Marв”ңВЎa Magdalena".', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65230400, -0.87365400, '0101000020E61000006FA0C03BF9F4EBBF66868DB27ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688755579.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688755579.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688755579/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23536, 'Plaza de la Magdalena 1930', '"La Universidad" (Plaza de la Magdalena).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65222400, -0.87323600, '0101000020E61000004D13B69F8CF1EBBF49D576137CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688776958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688776958.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688776958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23537, 'Puerta de la Universidad c.1965', 'Puerta de la Universidad de Zaragoza en la plaza de la Magdalena.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65211300, -0.87332200, '0101000020E6100000F1129CFA40F2EBBFF225547078D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14728749260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14728749260.webp', 'https://www.flickr.com/photos/zaragozaantigua/14728749260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23538, 'Pl. de la Magdalena 1677', 'Entrada de Carlos II en Zaragoza. Dibujo, 1910. El 1 de mayo de 1677 el rey Carlos II jurв”ңв”Ӯ los Fueros de Aragв”ңв”Ӯn en la Seo de Zaragoza, y el 14 daban comienzo, en presencia del monarca, las Cortes del Reino. Las Cortes se celebraron finalmente en Zaragoza, y no en Calatayud, como estaba previsto inicialmente. El rey permaneciв”ңв”Ӯ en la capital aragonesa hasta el 2 de junio. Fuente: reinadodecarlosii.blogspot.com.es/2012/03/las-relaciones-...', 1677, 1677, 1677, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15033442500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15033442500.webp', 'https://www.flickr.com/photos/zaragozaantigua/15033442500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23541, 'Puerta del Sol 1749', '"Puerta del Sol", Antonio Callaved, 2011. Esta puerta cerraba la ciudad al final del actual Coso Bajo, junto a las Tenerв”ңВЎas. Fue construida en 1749 y derribada en el siglo XIX. La piedra con un sol tallado que la coronaba se conserva en el Museo de Zaragoza. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1749, 1749, 1749, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092631837.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092631837.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092631837/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23542, 'Incendio discoteca Flying 1990', 'Foto Eduardo Bayona/El Periв”ңв”Ӯdico de Aragв”ңв”Ӯn. La madrugada del domingo 14 de enero de 1990 se produjo un incendio en la discoteca Flying, sita en la esquina de la calle Trinidad con Don Teobaldo. Murieron 43 personas. En la imagen podemos ver varios de los cadв”ңГӯveres depositados en el exterior de la sala, en la calle Trinidad.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65333800, -0.87267200, '0101000020E6100000335184D4EDECEBBFF59D5F94A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15161776125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15161776125.webp', 'https://www.flickr.com/photos/zaragozaantigua/15161776125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23544, 'Pl. de San Agustв”ңВЎn 1964', 'Celebracioes festivas en la plaza de San Agustв”ңВЎn en 1964. Fuente: www.facebook.com/photo.php?fbid=385217108301791&set=o...', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65090800, -0.87080100, '0101000020E6100000FF5E0A0F9ADDEBBF365A0EF450D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15738315929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15738315929.webp', 'https://www.flickr.com/photos/zaragozaantigua/15738315929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23545, 'Calle de la Universidad 1954', 'Chiquillerв”ңВЎa jugando entre claroscuros en la calle de la Universidad. Una canciв”ңв”Ӯn infantil parece escucharse entre risas: Al corro de la patata, comeremos ensalada, como comen los seв”ңв–’ores, naranjitas y limones... Al fondo, la plaza de la Magdalena, y a la izquierda e inmediata, la calle de la Trinidad. Este entorno, luego desaparecido, sв”ңв”Ӯlo perdura ya en la memoria, como sucede con el que fuera trenque de la muralla de piedra, la plaza del Estudio, y los colegios de San Vicente Ferrer, de la Trinidad y de San Juan Bautista de los Navarros. Y por supuesto el edificio de la vieja Universidad, entre las puertas de Valencia y del Sol. En la solana de la imagen, entrada del viejo Instituto Goya, denominaciв”ңв”Ӯn desde 1933 del anterior Instituto de Segunda Enseв”ңв–’anza de la Magdalena. Fuente visual: Foto Pomarв”ңв”Ӯn.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65329800, -0.87267200, '0101000020E6100000335184D4EDECEBBF6745D4449FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16166489434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16166489434.webp', 'https://www.flickr.com/photos/zaragozaantigua/16166489434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23546, 'Las Tenerв”ңВЎas 1591', 'F. Mota es el nombre con el que firmaba sus trabajos el pintor Fernando Fernв”ңГӯndez Mota, ilustrador de publicaciones entre finales del XIX y principios del XX. En este caso, se trata de otro interesante ejercicio de reinvenciв”ңв”Ӯn histв”ңв”Ӯrica propio del nacionalismo romв”ңГӯntico decimonв”ңв”Ӯnico, aquв”ңВЎ centrado en los extraв”ңв–’os sucesos y alteraciones del verano de 1591. Esta imagen es muestra de los desvarв”ңВЎos que dichas alteraciones produjeron en el imaginario romв”ңГӯntico-conservador. Tomando una reciente fotografв”ңВЎa del francв”ңВ®s Jean Laurent de un pedazo del lienzo de las murallas medievales de las Tenerв”ңВЎas, este pintor ceutв”ңВЎ F. Mota agrega unos desorientados soldados que parecen sacados de una expediciв”ңв”Ӯn del extremeв”ңв–’o Pizarro al otro lado del charco, y construye una representaciв”ңв”Ӯn considerada "pintura histв”ңв”Ӯrica". Que los soldados estв”ңГӯn desorientados, es literal: viniendo desde Utebo (como dicen las crв”ңв”Ӯnicas histв”ңв”Ӯricas), en lugar de entrar por la puerta de Sancho, la del Portillo, o incluso la de Baltax, esta tropa habrв”ңВЎa dado la vuelta a la ciudad, hasta buscar el ingreso por la Portaza. Mientras tanto, la ciudad, al fondo, esperando pacientemente a ser "conquistada". Fuente visual: Г”ГҮВЈEntrada de las tropas castellanas en ZaragozaГ”ГҮГҳ, Fernando Fernв”ңГӯndez Mota, 1919.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17666352789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17666352789.webp', 'https://www.flickr.com/photos/zaragozaantigua/17666352789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23547, 'Coso Bajo 1959', 'Imagen del punto donde la antigua calle de San Lorenzo desemboca en el Coso. El edificio central, esquinero entre ambas calles, con el aв”ңв–’adido del pequeв”ңв–’o de su derecha, varias dв”ңВ®cadas despuв”ңВ®s serв”ңГӯ reinventado en nueva planta. Los demв”ңГӯs edificios, perduran. Fuente visual: "Aragв”ңв”Ӯn. Cuatro ensayos", 1960, Banco de Aragв”ңв”Ӯn.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65171100, -0.87362700, '0101000020E610000009E23C9CC0F4EBBFC3B81B446BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18797925412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18797925412.webp', 'https://www.flickr.com/photos/zaragozaantigua/18797925412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22167, 'Vista aв”ңВ®rea Las Fuentes 1955', 'Vista aв”ңВ®rea del nв”ңв•‘cleo inaugural del barrio de Las Fuentes: las viviendas para tranviarios llamadas Grupo Vizconde de Escoriaza, levantadas en 1953, y la primera fase del grupo de viviendas "Josв”ңВ® Antonio Girв”ңв”Ӯn", de 1955. En 1957, el tranvв”ңВЎa ampliarв”ңГӯ sus servicios hasta aquв”ңВЎ, con la inauguraciв”ңв”Ӯn de su lв”ңВЎnea 17 "Las Fuentes". Al fondo, el rв”ңВЎo Ebro y la ciudad consolidada. Fuente: TAF Helicв”ңв–“pters. Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'LAS FUENTES', 41.64833000, -0.85835400, '0101000020E61000004D81CCCEA277EBBF0282397AFCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30989909240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30989909240.webp', 'https://www.flickr.com/photos/zaragozaantigua/30989909240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23548, 'Pl. de la Magdalena 1591', '"Motв”ңВЎn en Zaragoza en defensa de los Fueros". Ilustraciв”ңв”Ӯn de Fernando Fernв”ңГӯndez Mota, 1910 La fantasв”ңВЎa recreacionista asociada a la instrumentalizaciв”ңв”Ӯn polв”ңВЎtica del pasado histв”ңв”Ӯrico, en ocasiones genera escenarios delirantes como el presente, en el que el autor de la ilustraciв”ңв”Ӯn sitв”ңв•‘a una acciв”ңв”Ӯn de 1591 en un entorno imposible en el barrio de la Magdalena de esa в”ңВ®poca: la Puerta de Valencia se ha evaporado, siendo que fue derribada casi tres siglos despuв”ңВ®s (1867), y la puerta de acceso a la iglesia parroquial de la Magdalena es recolocada tal y como quedarв”ңГӯ tras su orientaciв”ңв”Ӯn de 1730 (hasta entonces, por la calle Mayor), e incluso aparece la portada neoclв”ңГӯsica que le serв”ңГӯ aв”ңв–’adida mв”ңГӯs tarde, en 1758. Si este es el escenario de la Magdalena de 1591, cв”ңв”Ӯmo serв”ңГӯn los sucesos que en ella acontecen. Fuente: Historia de Espaв”ңв–’a, Miguel Seguв”ңВЎ, 1910.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18965139881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18965139881.webp', 'https://www.flickr.com/photos/zaragozaantigua/18965139881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23549, 'Pedro Santisteve 1990', 'Pedro Santisteve (Zaragoza, 1958), abogado penalista y alcalde de Zaragoza desde 2015, sustituyendo a Juan Alberto Belloch (2003-2015). En la imagen, en el bar La Vв”ңВЎa Lв”ңГӯctea (Doctor Palomar 25) en 1990. Fuente: Asociaciв”ңв”Ӯn Cultural y Recreativa Barrio Verde de Zaragoza.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65113200, -0.87187600, '0101000020E61000007D5A457F68E6EBBF85B01A4B58D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19065572706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19065572706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19065572706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23550, 'Calle Mayor 1847', 'Dibujo de Josв”ңВ® Gв”ңв”Ӯmez Piquer de 1997, recreando el rincв”ңв”Ӯn de la calle Mayor nв”¬в•‘ 59 (a la izquierda, fuera de la imagen) donde fue instalada la Escuela Profesional de Veterinaria de Zaragoza en 1847, y hasta 1853. En las inmediaciones, en la esquina de la calle de Torrejв”ңв”Ӯn con Mayor, hoy sede del PCE en Aragв”ңв”Ӯn, tuvo su sede el Colegio de Nuestra Seв”ңв–’ora del Torrejв”ңв”Ӯn, colegio mayor universitario seglar fundado en 1602 y clausurado a mediados del siglo XIX. El dibujo supone la torre de la iglesia de La Magdalena sin su recrecimiento barroco, que sв”ңВЎ estaba en la fecha que se intenta reflejar. Fuente: Crв”ңв”Ӯnica de 150 aв”ңв–’os de estudios veterinarios en Aragв”ңв”Ӯn. IFC, 2000.', 1847, 1847, 1847, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19115291828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19115291828.webp', 'https://www.flickr.com/photos/zaragozaantigua/19115291828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23551, 'Coso Bajo 1984', 'Foto Arturo Burgos, 1984. Calle del Coso Bajo de Zaragoza en 1984, con visual de sus nв”ңв•‘meros pares en el tramo comprendido entre las plazas de La Magdalena y las Tenerв”ңВЎas. Fuente: Zaragoza, sus calles y su historia, 1984.', 1984, 1984, 1984, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19428864662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19428864662.webp', 'https://www.flickr.com/photos/zaragozaantigua/19428864662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23553, 'Plaza de la Magdalena 1960', 'Imagen del funeral, el 19 de octubre de 1960, de Carmelo Zaldв”ңВЎvar, jefe de administraciв”ңв”Ӯn del Ayuntamiento de Zaragoza. La comitiva se dirige, desde la calle Mayor, a la puerta de la iglesia de la Magdalena. En el lateral del templo se observa la capilla exterior adosada dedicada a San Cristв”ңв”Ӯbal, como el arco que tenв”ңВЎa enfrente en la calle del mismo nombre. AL fondo de la calle, el mercado de San Vicente de Paв”ңв•‘l, recayente a la vв”ңВЎa del mismo nombre. Fuente: AMZ.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20466773353.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20466773353.webp', 'https://www.flickr.com/photos/zaragozaantigua/20466773353/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23554, 'Calle del в”ңГҙrgano 1989', 'La calle del в”ңГҙrgano el 17 de febrero de 1989, en las traseras de la iglesia de La Magdalena, que debe su nombre al receptв”ңГӯculo de ese instrumento, que forma un pasadizo o arco sobre la vв”ңВЎa. En primer plano, el pilв”ңв”Ӯn de piedra ya desaparecido, como casi todos los de su entorno. La imagen estв”ңГӯ tomada desde la calle Mayor, con la de Martв”ңВЎn Carrillo al fondo. Fuente: "Memoria de las calles de Zaragoza", Juliв”ңГӯn Ruiz Marв”ңВЎn, Librerв”ңВЎa General, 2002.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21053815984.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21053815984.webp', 'https://www.flickr.com/photos/zaragozaantigua/21053815984/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23557, 'Calle de Olleta 1967', 'Calle de Jusepillo de Olleta en 1967. Comienza en la de San Agustв”ңВЎn y termina en la de las Arcadas. La imagen estв”ңГӯ capturada justo antes de que la calle Barrioverde cruce la calle Olleta, ascendente y adoquinada de izquierda a derecha. Al fondo, a la izquierda, se deriva la calle de Luzв”ңГӯn. Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65219900, -0.87368200, '0101000020E6100000EB5223F433F5EBBFF1BDBF417BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22728082717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22728082717.webp', 'https://www.flickr.com/photos/zaragozaantigua/22728082717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23560, 'Calle San Cristв”ңв”Ӯbal 1965', 'Insв”ңв”Ӯlita imagen, posiblemente de la antigua plazuela de Juan del Corral, como ensanche de la calleja de San Cristв”ңв”Ӯbal de la Magdalena, que conectaba la calle de San Lorenzo, al fondo, con la calle Mayor, en este caso bajo un arquitrabado arco nominado tambiв”ңВ®n "de San Cristв”ңв”Ӯbal". De ser asв”ңВЎ, esta plazuela tendrв”ңВЎa relaciв”ңв”Ӯn con el lugar donde estuvo la casa solariega de esta familia infanzona de caballeros hidalgos, apellidados del Corral, o Ximв”ңВ®nez del Corral, que se establecieron en la ciudad en el siglo XVII. Unos aв”ңв–’os despuв”ңВ®s de esta captura fotogrв”ңГӯfica, el entorno edificatorio fue bastante transformado, aunque la plazuela mantiene su planta de "quesito" (mв”ңГӯs o menos). Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65212200, -0.87414100, '0101000020E6100000B1F7E28BF6F8EBBF4580D3BB78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22758258227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22758258227.webp', 'https://www.flickr.com/photos/zaragozaantigua/22758258227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23561, 'Calle Olleta 1967', 'Calle de Jusepillo de Olleta en 1967. Comienza en la de San Agustв”ңВЎn y termina en la de las Arcadas. Hoy radicalmente transformada. La imagen estв”ңГӯ capturada, precisamente, donde la calle Olleta desembocaba en la calle de las Arcadas, cuyo antiguo (y desaparecido) azulejo nв”ңв•‘mero 21, bajo el de la aseguradora de incendios, referencia el lugar. Los tendedores con cuerda, y una prenda a secar, seв”ңв–’ales de moradores. Fuente visual: Foto Leonardo Pв”ңВ®rez Obis, donada por в”ңГјngel Hernв”ңГӯndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65219900, -0.87187900, '0101000020E6100000C136E2C96EE6EBBFF1BDBF417BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22826932950.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22826932950.webp', 'https://www.flickr.com/photos/zaragozaantigua/22826932950/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23565, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en el tramo de los antiguos y dispares nв”ңв•‘meros impares entre la calle de San Lorenzo (izquierda) y la plaza de la Magdalena (a la derecha, fuera de plano). Este tramo serв”ңВЎa profundamente remodelado aв”ңв–’os despuв”ңВ®s. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65182500, -0.87363700, '0101000020E6100000EC6AF294D5F4EBBF8CDB68006FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24834862868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24834862868.webp', 'https://www.flickr.com/photos/zaragozaantigua/24834862868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23566, 'Plaza de la Magdalena 1960', 'Imagen, desde cierta altura, de la sesentera plaza de la Magdalena durante el funeral de Carmelo Zaldв”ңВЎvar, jefe de administraciв”ңв”Ӯn del Ayuntamiento. A la izquierda, la calle Mayor. En el centro, la iglesia parroquial de Santa Marв”ңВЎa Magdalena, funcional, y con el remate barroco de la torre. A la derecha, el edificio de la antigua Universidad Literaria (hasta 1958 sede del Instituto Goya), y el que fuera colegio de San Juan Bautista. Por encima, despuntan dos torres pilaristas. Fuente visual: Archivo Municipal de Zaragoza.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65223900, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25499727161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25499727161.webp', 'https://www.flickr.com/photos/zaragozaantigua/25499727161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23568, 'Pl. de San Agustв”ңВЎn 1991', 'Imagen parcial de la plaza de San Agustв”ңВЎn capturada desde el final de la calle Viola, con vista del espacio donde desembocan las calles de San Agustв”ңВЎn y de las Arcadas. A la derecha, parte del antiguo convento y cuartel de San Agustв”ңВЎn que luego serв”ңВЎa reformada para acoger la biblioteca municipal Marв”ңВЎa Moliner. Fuente visual: AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65116000, -0.87126600, '0101000020E61000004DBC033C69E1EBBF4F3BFC3559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28318398369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28318398369.webp', 'https://www.flickr.com/photos/zaragozaantigua/28318398369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23569, 'Calle Martв”ңВЎn Carrillo aв”ңв–’os 30', 'Acuarela de Ambrosio Ruste representando la calle de Martв”ңВЎn Carrillo, con la iglesia de la Magdalena a la derecha y la plaza homв”ңв”Ӯnima al fondo. Fuente: Lв”ңГӯminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65255000, -0.87373700, '0101000020E6100000CEC3094CA7F5EBBF9D8026C286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31595527374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31595527374.webp', 'https://www.flickr.com/photos/zaragozaantigua/31595527374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23573, 'Pl. Magdalena 1931', 'Foto: Miguel Marв”ңВЎn Chivite. "Animado aspecto de las puertas del colegio electoral instalado en la Universidad, durante la maв”ңв–’ana del domingo" 12 de abril de 1931, dв”ңВЎa de las elecciones municipales, cuyo resultado determinв”ңв”Ӯ la llegada de la Segunda Repв”ңв•‘blica dos dв”ңВЎas despuв”ңВ®s. Fuente: Heraldo de Aragв”ңв”Ӯn.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65218900, -0.87338300, '0101000020E61000005C3CBCE7C0F2EBBFCDE7DCED7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31898187726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31898187726.webp', 'https://www.flickr.com/photos/zaragozaantigua/31898187726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23574, 'Plaza de la Universidad c.1929', 'Imagen de la monumental escalera de la antigua Universidad Literaria de la Magdalena. Esta fue una de las destacadas piezas que Ricardo Magdalena dio nuevo empaque en la gran reforma acometida entre 1907-1912. De 1925 es el elemento que centraliza la imagen, una lв”ңГӯpida que fue inaugurada durante la Dictadura de Primo de Rivera, con presencia del rey Alfonso XIII, en homenaje a los estudiantes valencianos muertos en los asedios de Zaragoza en 1808-1809. Cuando en 1967 este lugar fue derribado, la lв”ңГӯpida fue demediada y reinstalada sin atributos identificativos en un insв”ңв”Ӯlito establecimiento de la ciudad. Oficialmente se la dio por desaparecida, de forma que la lв”ңГӯpida que hoy se encuentra en el actual Paraninfo de la plaza de Paraв”ңВЎso es una reproducciв”ңв”Ӯn de la lв”ңГӯpida que, sobre el mismo asunto, fue inaugurada en 1924 en la Universidad de Valencia. Parece enrevesado, aunque tal vez sв”ңв”Ӯlo sea que Zaragoza tiene complejas sinuosidades que fluyen en el mar de fondo de su acontecer histв”ңв”Ӯrico, bajo una engaв”ңв–’osa apariencia de simplicidad. Fuente visual: foto Juan Mora Insa, en elblogdezaragoza.blogspot.com.es/', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65283500, -0.87293900, '0101000020E6100000EBE40CC51DEFEBBF9357E71890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32214302646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32214302646.webp', 'https://www.flickr.com/photos/zaragozaantigua/32214302646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23576, 'Coso Bajo 1814', '"Entrada triunfal de Fernando VII en Zaragoza". в”ңГҙleo sobre lienzo, Miguel Parra Abril, 1818. La escena representa la visita de Fernando VII a Zaragoza, el 6 de abril de 1814. La comitiva estaba formada tambiв”ңВ®n por su hermano Carlos Marв”ңВЎa Isidro, el duque de San Carlos y Josв”ңВ® Palafox. Entraron por el puente de Piedra, siguieron por las Tenerв”ңВЎas, pasaron por la plaza de la Magdalena y subieron por el Coso hasta llegar al palacio de Sв”ңГӯstago. El rey estuvo en Zaragoza hasta el 11 de abril. El escenario escogido para el cuadro es el tramo del Coso Bajo con las simbв”ңв”Ӯlicas ruinas del seminario, tomando como modelo el grabado de Gв”ңГӯlvez y Brambila de 1814 "Ruinas del Seminario". Se trata del edifico que se ve al fondo, entre las calles de San Jorge y San Lorenzo. Fuente visual: Palacio Real de Madrid.', 1814, 1814, 1814, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65158800, -0.87421900, '0101000020E61000009F56D11F9AF9EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32856669552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32856669552.webp', 'https://www.flickr.com/photos/zaragozaantigua/32856669552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23578, 'Universidad Literaria c.1929', 'Imagen capturada en el descansillo de la monumental escalera de la Universidad Literaria de la Magdalena, una de las destacadas piezas que Ricardo Magdalena habв”ңВЎa reformado en 1907-1912 dв”ңГӯndole este imponente aspecto. En la planta baja, acceso desde el vestв”ңВЎbulo recayente a la plaza de la Magdalena y ventanas a la galerв”ңВЎa del patio de luces. Toda esta zona quedв”ңв”Ӯ convertida en un campo de cascotes cuando el edificio fue derribado a finales de la prodigiosa dв”ңВ®cada de los aв”ңв–’os sesenta, que terminaron depositados en uno de los abundantes vertederos de escombros que jalonaban la periferia de una ciudad ensimismada en la modernidad y progreso. Fuente visual: foto Juan Mora Insa, en elblogdezaragoza.blogspot.com.es/', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65218900, -0.87338300, '0101000020E61000005C3CBCE7C0F2EBBFCDE7DCED7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34922119006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34922119006.webp', 'https://www.flickr.com/photos/zaragozaantigua/34922119006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23580, 'Calle del Rв”ңВЎo 1986', 'Imagen capturada desde el solar de los antiguos talleres y almacenes municipales de la Rebolerв”ңВЎa y centrada en los edificios de vivienda de los antiguos nв”ңв•‘meros 16, 18, 29 y 22 de la calle del Rв”ңВЎo. A la derecha, ingreso al callejв”ңв”Ӯn del Rв”ңВЎo. A la izquierda, esquinero y moderno bloque del nв”¬в•‘ 18 de la calle Monreal. Aв”ңв–’os despuв”ңВ®s, estos inmuebles serв”ңВЎan derribados y sustituidos por el moderno bloque del nв”¬в•‘ 18 de la calle del Rв”ңВЎo. Justo enfrente serв”ңВЎa construido otro nuevo bloque correspondiente a los actuales nв”¬в•‘ 7, 9 y 11 de la misma calle, junto al CEIP (Colegio Pв”ңв•‘blico de Educaciв”ңв”Ӯn Infantil y Primaria) y al Pabellв”ңв”Ӯn Deportivo Municipal Tenerв”ңВЎas. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65343700, -0.87010700, '0101000020E610000058A9A0A2EAD7EBBF887FD8D2A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37743144235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37743144235.webp', 'https://www.flickr.com/photos/zaragozaantigua/37743144235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23581, 'Iglesia Magdalena c.1966', 'Vista de la iglesia de Santa Marв”ңВЎa Magdalena cuando comienzan a desmocharle la torre para devolverle el probable aspecto original, eliminando su remate barroco.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65253300, -0.87391700, '0101000020E6100000CC63CDC820F7EBBFC7478B3386D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38037597074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38037597074.webp', 'https://www.flickr.com/photos/zaragozaantigua/38037597074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23582, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en los solares y antiguos edificios correspondientes a los nв”ңв•‘meros 170, 172 y 174 del Coso, y el nв”ңв•‘mero 5 del arranque de la calle de San Agustв”ңВЎn (a la derecha). Desde finales de la dв”ңВ®cada siguiente estos inmuebles serв”ңВЎan derribados y sobre sus solares se levantarв”ңВЎan las actuales viviendas que allв”ңВЎ se ubican. Al fondo, a la derecha, el nв”¬в•‘ 2 de la calle de Jusepillo Olleta. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65204200, -0.87292900, '0101000020E6100000075C57CC08EFEBBF29CFBC1C76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38580739381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38580739381.webp', 'https://www.flickr.com/photos/zaragozaantigua/38580739381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23583, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en los antiguos edificios (de finales del siglo XIX) correspondientes a los nв”ңв•‘meros 174 (parcial), 176, 178 y 180, esquinero con el arranque de la calle de Alcober, de la que se muestran las fachadas de los nв”ңв•‘meros 1, 3 y 5. De todos ellos perdura el nв”ңв•‘mero 180. El resto fueron luego derribados, bien para dar paso a modernas construcciones habitacionales (actual nв”ңв•‘mero 174), bien para "esponjar" esta zona ubicada entra las plazas de la Magdalena, Tenerв”ңВЎas, y San Agustв”ңВЎn mediante un solar habilitado para uso pв”ңв•‘blico (esquina Alcober-Coso). Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65241900, -0.87253200, '0101000020E6100000C3D4963AC8EBEBBFFF243E7782D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38639236771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38639236771.webp', 'https://www.flickr.com/photos/zaragozaantigua/38639236771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23584, 'Convento de San Agustв”ңВЎn 1809', 'Imagen del costumbrista в”ңв”Ӯleo sobre lienzo &quot;Heroica defensa de la torre de San Agustв”ңВЎn en Zaragoza en la Guerra de la Independencia&quot; pintado por Cв”ңВ®sar в”ңГјlvarez Dumont en 1884, posiblemente basado en el Episodio Nacional de Benito Pв”ңВ®rez Galdв”ңв”Ӯs, &quot;Zaragoza&quot;. Los verв”ңВЎdicos hechos referidos sucedieron durante el segundo asedio de la ciudad por las tropas francesas, en febrero de 1809. El в”ңв”Ӯleo centra la atenciв”ңв”Ӯn en el interior de la torre del convento de San Agustв”ңВЎn y unos peleones paisanos dispuestos en colorista y triangular composiciв”ңв”Ӯn que culmina en la campana de la torre. A la izquierda, una gran bota de vino y varios grafitis patriв”ңв”Ӯticos en la pared, entre los que destacan &quot;gabacho&quot;, despectiva denominaciв”ңв”Ӯn del francв”ңВ®s desde el siglo XVII y &quot;Pepe Botella&quot;, capciosa referencia al rey Josв”ңВ® I Bonaparte. Fuente visual: www.museodelprado.es', 1809, 1809, 1809, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65090300, -0.87077200, '0101000020E61000006BB8C83D5DDDEBBF24EF1CCA50D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39937575692.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39937575692.webp', 'https://www.flickr.com/photos/zaragozaantigua/39937575692/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23585, 'Calle de San Cristв”ңв”Ӯbal c.1965', 'Imagen capturada en la antigua calle de San Cristв”ңв”Ӯbal con una interesante vista parcial de la torre de la iglesia parroquial de la Magdalena emergiendo entre antiguas viviendas de la calle Mayor, construidas en el siglo XVI y muy reformadas en el XIX. El remate de la torre seguв”ңВЎa siendo el tradicional desde в”ңВ®poca barroca. Fuente visual: foto Palacio, AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65225800, -0.87401200, '0101000020E61000003CF88903E8F7EBBFF646AD307DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40580927171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40580927171.webp', 'https://www.flickr.com/photos/zaragozaantigua/40580927171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23586, 'Calle de Josв”ңВ® Palafox 1991', 'Imagen centrada en el solar conformado tras el derribo del nв”¬в•‘ 31 de la calle de Josв”ңВ® Palafox (tramo antiguamente denominado de San Vicente) y el nв”¬в•‘ 15 de la calle Universidad (antigua de la Trinidad), tras una transitoria y colorista remodelaciв”ңв”Ӯn hasta que se llevara a cabo el correspondiente desarrollo urbanв”ңВЎstico. Este solar lindaba, a la izquierda, con el antiguo Laboratorio Quв”ңВЎmico Municipal construido en 1914 segв”ңв•‘n proyecto del arquitecto municipal Josв”ңВ® de Yarza Echenique. A la derecha, los nв”ңв•‘meros 16 y 14 de la calle de Don Teobaldo, construidos en la dв”ңВ®cada de los aв”ңв–’os treinta, y fachada del convento de las Canonesas Regulares del Santo Sepulcro. Pocos aв”ңв–’os despuв”ңВ®s, sobre este solar serв”ңВЎa construido el actual nв”¬в•‘ 18 de la calle de Don Teobaldo. Fuente visual: AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65328400, -0.87295000, '0101000020E6100000E561A1D634EFEBBF028063CF9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42332210674.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42332210674.webp', 'https://www.flickr.com/photos/zaragozaantigua/42332210674/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23587, 'Calle de Alonso V 1986', 'Imagen capturada en la calle de Alonso V y centrada en el tramo de los inmuebles de los nв”ңв•‘meros 6-12 (de derecha a izquierda), adosados desde finales del siglo XIX sobre la muralla medieval de ladrillo que delimitaba la ciudad en esta zona, dejando extramuros a la rebolerв”ңВЎa, al otro lado de la entonces calle de las Tenerв”ңВЎas. El estrechisimo inmueble del nв”¬в•‘ 8, a la derecha del в”ңГӯrbol de la escena, se correspondв”ңВЎa con uno de los antiguos torreones que desde finales del siglo XVII habв”ңВЎa sido reconvertido en vivienda. Tras estos edificios circulaba la calle de las Arcadas, en el tramo donde a la izquierda desembocaba la calle de Jusepillo de Olleta. En el momento de tomar esta fotografв”ңВЎa se estaba procediendo a urbanizar la calle de Alonso V. Una intervenciв”ңв”Ӯn municipal posterior supuso la restauraciв”ңв”Ӯn y rehabilitaciв”ңв”Ӯn, previo derribo de las viviendas adosadas, de este y otros dos torreones, ademв”ңГӯs de algunos inmediatos lienzos del tramo de muralla medieval. En este caso la rehabilitaciв”ңв”Ӯn del oculto torreв”ңв”Ӯn tuvo que ser forzosamente muy creativa.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65252900, -0.87143800, '0101000020E610000095BBCFF1D1E2EBBF8658FD1186D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48108411727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48108411727.webp', 'https://www.flickr.com/photos/zaragozaantigua/48108411727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23588, 'Calle de Alonso V 1986', 'Imagen capturada en la calle de Alonso V y centrada en el tramo de los inmuebles de los nв”ңв•‘meros 10-16 (de derecha a izquierda), adosados desde finales del siglo XIX sobre la muralla medieval de ladrillo que delimitaba la ciudad en esta zona, dejando extramuros a la rebolerв”ңВЎa, al otro lado de la entonces calle de las Tenerв”ңВЎas. El inmueble del nв”¬в•‘ 16, a la izquierda, se habв”ңВЎa construido previo derribo del tercero de los antiguos cubos de la muralla, desde la antigua puerta de la Portaza, luego del Sol. Tras estos edificios circulaba la calle de las Arcadas y el desemboque en la misma de la calle de Jusepillo de Olleta. En el momento de tomar esta fotografв”ңВЎa se estaba procediendo a urbanizar la calle de Alonso V. Una intervenciв”ңв”Ӯn municipal posterior supuso la restauraciв”ңв”Ӯn creativa, previo derribo de las viviendas adosadas, de este tramo de la muralla medieval, y se apuntв”ңв”Ӯ la preexistencia del referido y desaparecido cubo de la muralla con una reconstrucciв”ңв”Ӯn parcial.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65244800, -0.87127800, '0101000020E61000005E2D776682E1EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48114400817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48114400817.webp', 'https://www.flickr.com/photos/zaragozaantigua/48114400817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23590, 'Calle de Martв”ңВЎn Carrillo 1991', 'Imagen capturada desde cierta altura en el inmueble del nв”¬в•‘ 5 de la calle del в”ңГҙrgano, y centrada los modernos edificios residenciales que a la izquierda se extienden en esta manzana desde la calle de Torrellas, la plaza de Asso (nв”¬в•‘ 6) la calle de Martв”ңВЎn Carrillo (nв”¬в•‘ 3, 5 y 7) y hasta la calle de la Universidad. Fueron proyectados por los arquitectos Teв”ңв”Ӯfilo Martв”ңВЎn Sв”ңГӯenz y Luis Fernв”ңГӯndez Ramв”ңВЎrez sobre los solares de antiguas casonas en esta parte del barrio de la Magdalena, incluyendo la fotogв”ңВ®nica Casa Tejada. En primer tв”ңВ®rmino, aspecto de la calle de Martв”ңВЎn Carrillo tras la urbanizaciв”ңв”Ӯn integral de esta zona, dotв”ңГӯndola de nuevo mobiliario urbano, arbolado, iluminaciв”ңв”Ӯn e incluyendo itinerarios peatonales. A la izquierda, las referidas viviendas residenciales aв”ңв•‘n sin ocupar, y con los bajos comerciales tapiados de obra y aв”ңв•‘n vacantes. A la derecha, lienzo norteв”ңв–’o de la iglesia parroquial de Santa Marв”ңВЎa Magdalena. Al fondo y a la izquierda, el IES Pedro de Luna, recayente a la plaza de la Magdalena y construido donde estuviera la homв”ңв”Ӯnima universidad. Tras el Coso Bajo, vista parcial del solar tras derribo del nв”¬в•‘ 164, esquinero con la calle de Alejandro Palomar y construido algunos aв”ңв–’os despuв”ңВ®s.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50262950396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50262950396.webp', 'https://www.flickr.com/photos/zaragozaantigua/50262950396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23591, 'Discoteca Flying 1990', 'Terrible matinal del domingo 14 de enero de 1990 tras el incendio en la discoteca Flying sita en la esquina de la calle de Don Teobaldo, desde donde se ha capturado esta imagen, con la de la Trinidad, que por la derecha y hacia el fondo desciende hasta el Coso Bajo. En primer tв”ңВ®rmino, ingreso al local siniestrado en el que murieron 43 personas, con rastros en la fachada de las tв”ңв”Ӯxicas emanaciones causantes de la catв”ңГӯstrofe.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65330600, -0.87259700, '0101000020E610000089CE328B50ECEBBFEA23F0879FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50307864071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50307864071.webp', 'https://www.flickr.com/photos/zaragozaantigua/50307864071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23593, 'Calle de San Lorenzo 1991', 'Imagen del tramo final de la calle de San Lorenzo, con su tradicional pequeв”ңв–’o comercio (como "Casa Paco. Novelas-Revistas", a la izquierda) y "aceras" liliputienses, capturada desde el desemboque en el Coso Bajo. Inmediato y a la derecha, vista parcial del gran solar resultante del derribo de los antiguos inmuebles de los nв”ңв•‘meros 53 y 55 de esta calle y de los nв”ңв•‘meros 135 y 137 del Coso, refundidos poco tiempo despuв”ңВ®s en el moderno inmueble del nв”¬в•‘ 137 del Coso. Hacia el fondo y a la izquierda, Arranque de la calle de los Pelegrв”ңВЎn y vista del esquinero inmueble del nв”¬в•‘ 51 de la calle de San Lorenzo, que a finales de la dв”ңВ®cada serв”ңГӯ derribado y sustituido por el actual nв”¬в•‘ 1 de los Pelegrв”ңВЎn.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65178300, -0.87377700, '0101000020E61000005CE7DF2EFBF5EBBF5D8B16A06DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50439910588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50439910588.webp', 'https://www.flickr.com/photos/zaragozaantigua/50439910588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23594, 'Calle de Aв”ңв–’в”ңв”Ӯn 1991', 'Imagen capturada en la calle de Pedro Garcв”ңВ®s Aв”ңв–’в”ңв”Ӯn durante la construcciв”ңв”Ӯn, a la derecha, de las 45 viviendas municipales de alquiler levantadas sobre el gran solar dejado tras el derribo de los antiguos inmuebles de los nв”ңв•‘meros 5-7, 9 y 11-13 de esta calle, ademв”ңГӯs del nв”¬в•‘ 5-7 de la calle del Heroв”ңВЎsmo. El ingreso a las viviendas desde donde se ha realizado la imagen estaba proyectado mediante un gran espacio interior porticado que recibirв”ңВЎa el nombre de plaza de Aв”ңв–’в”ңв”Ӯn. Esta gran manzana delimitada entre las calles del Heroв”ңВЎsmo, Cantв”ңВЎn y Gamboa, la Torre y Aв”ңв–’в”ңв”Ӯn resultв”ңв”Ӯ ser rica en restos arqueolв”ңв”Ӯgicos que aв”ңв–’os mв”ңГӯs tarde, con motivo de nuevas excavaciones en esta в”ңв•‘ltima calle, donde estuvieran los derribados inmuebles nв”¬в•‘ 21 y 23, revelarв”ңВЎan las estructuras arquitectв”ңв”Ӯnicas de varias destacadas "domus" romanas de la dinastв”ңВЎa Julio-Claudia, abandonadas a finales del siglo I de nuestra era, donde se encontraron los restos del mejor conjunto de bienes muebles y decoraciones domв”ңВ®sticas de la colonia Caesaraugusta. Al fondo de la imagen, arranque de la calle de Aв”ңв–’в”ңв”Ӯn desde la del Heroв”ңВЎsmo.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65070100, -0.87352000, '0101000020E610000087DC0C37E0F3EBBFBC3C9D2B4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50494632363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50494632363.webp', 'https://www.flickr.com/photos/zaragozaantigua/50494632363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23595, 'La Magdalena, 1865', 'Iglesia de Santa Marв”ңВЎa Magdalena recreada con el supuesto aspecto que tenв”ңВЎa antes de la gran reforma barroca que en 1727-30 reorientв”ңв”Ӯ su entrada principal, pasando de la calle Mayor a la antigua cabecera del templo, en la plaza de la Magdalena, y recreciв”ңв”Ӯ la original torre con un remate que aquв”ңВЎ aparece en color mв”ңГӯs atenuado y que perdurв”ңв”Ӯ hasta que fue eliminado en la rehabilitaciв”ңв”Ӯn de 1970. El punto de vista estв”ңГӯ tomado desde la plaza de la Magdalena, quedando a la izquierda la calle Mayor, y a la derecha la calle de Martв”ңВЎn Carrillo. A espaldas quedaba la Puerta de Valencia.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65235200, -0.87378800, '0101000020E61000005664744012F6EBBF77BD344580D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50880882348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50880882348.webp', 'https://www.flickr.com/photos/zaragozaantigua/50880882348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24020, 'Calle Monreal 2002', 'En marzo de 2002 se celebrв”ңв”Ӯ en Zaragoza una "reuniв”ңв”Ӯn informal" de Ministros de Defensa de la Uniв”ңв”Ӯn Europea. El Foro Zaragoza 2002, formado por cerca de 40 asociaciones, convocв”ңв”Ӯ un acto antimilitarista ante la puerta de la fв”ңГӯbrica de armas Instalaza, en la calle Monreal 27. Esta empresa, fundada en 1943, "es una compaв”ңв–’ia de vanguardia que aplica las в”ңв•‘ltimas tecnologв”ңВЎas en el diseв”ңв–’o, desarrollo y fabricaciв”ңв”Ӯn de equipos y material para ofrecer soluciones eficaces". Sus productos "equipan a las fuerzas armadas de paв”ңВЎses de todo el mundo, con resultados muy satisfactorios y con un mв”ңГӯximo nivel de operatividad y eficacia". Fuente: Agencia EFE.', 2002, 2002, 2002, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65244700, -0.86942200, '0101000020E61000007F880D164ED2EBBFC9AF1F6283D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24629717866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24629717866.webp', 'https://www.flickr.com/photos/zaragozaantigua/24629717866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24220, 'Pl. de la Magdalena 1872', 'Dibujo: Pradilla; grabado: Severini. 1872. "Zaragoza. Fiestas del Pilar. Cabalgata histв”ңв”Ӯrica de don Jaime el Conquistador." Grabado con la recreaciв”ңв”Ӯn histв”ңв”Ӯrica de la entrada del rey Jaime I el Conquistador en la ciudad de Valencia el 28 de septiembre de 1238. Esta cabalgata fue incluida en el programa de las Fiestas del Pilar, y en la imagen se adentra en el Coso Bajo proveniente de la calle Mayor. Al fondo, la plaza de la Magdalena. Unos aв”ңв–’os antes se habв”ңВЎa dado el nombre de Don Jaime I a uno de los principales viales de la ciudad. Fuente: "La Ilustraciв”ңв”Ӯn Espaв”ңв–’ola y Americana", Madrid, Aв”ңв–’o XVI, nв”¬в•‘ XLII, 08-11-1872.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15283479654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15283479654.webp', 'https://www.flickr.com/photos/zaragozaantigua/15283479654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24414, 'Tenerв”ңВЎas 1942', 'Imagen de la capilla habilitada en el cuartel del Grupo de Automв”ңв”Ӯviles del 5в”¬в•‘ Cuerpo de Ejв”ңВ®rcito, ubicado desde 1937 en la confluencia de la calle del Asalto, la plaza de las Tenerв”ңВЎas, y la ribera del Ebro. Una buena muestra de la abrumadora memoria histв”ңв”Ӯrica de la guerra de 1936-39, el perenne homenaje a los muertos durante la Cruzada, y la в”ңВЎntima relaciв”ңв”Ӯn entre fuerzas armadas, e iglesia catв”ңв”Ӯlica. Fuente: Archivo Coyne. AHPZ', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65370900, -0.87120100, '0101000020E610000087C267EBE0E0EBBFE90C8CBCACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32796858004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32796858004.webp', 'https://www.flickr.com/photos/zaragozaantigua/32796858004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24879, 'Muralla medieval c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Cв”ңВЎa. 1872-1879. Titulado "Torreв”ңв”Ӯn del Trovador", se trata de una de las torres de la muralla medieval de rв”ңВ®jola, en la actual calle de Alonso V.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65237600, -0.87120600, '0101000020E6100000F986C267EBE0EBBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14843226426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14843226426.webp', 'https://www.flickr.com/photos/zaragozaantigua/14843226426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24911, 'Muralla medieval 2013', 'Foto: Rusolera, abril de 2013. El 6 de abril de 2013 se derrumbв”ңв”Ӯ parte del lienzo de la muralla medieval de Zaragoza, entre la calle de Alonso V y la de las Arcadas. Unos 25 metros, que fueron repuestos meses despuв”ңВ®s. Fuente: zaragozaciudad.net/zaragozafluye/2014/091801-muralla-medi...', 2013, 2013, 2013, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65259200, -0.87125700, '0101000020E610000080272D5C56E1EBBFCCD0782288D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21494516160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21494516160.webp', 'https://www.flickr.com/photos/zaragozaantigua/21494516160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25964, 'Colegio San Agustв”ңВЎn 1994', 'Tras el desalojo del 23 de diciembre de 1993 de la Casa de la Paz, en el paseo de Sagasta 52, el colectivo de okupas de Zaragoza buscв”ңв”Ӯ un nuevo alojamiento en el abandonado colegio de San Agustв”ңВЎn, en el nв”ңв•‘mero 5 de la calle homв”ңв”Ӯnima, a principios de 1994, como ilustra la foto. Fueron desalojados en una semana. En mayo de 1996 volvieron a intentarlo.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65153900, -0.87181600, '0101000020E6100000292504ABEAE5EBBFC68844A165D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52492136001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52492136001.webp', 'https://www.flickr.com/photos/zaragozaantigua/52492136001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20960, 'La Lonja 1858', '"Town Hall Zaragoza". J.B. Waring (dib.) y T.H. Macquoid (lit.), 1858. Colecciв”ңв”Ӯn Pascual de Quinto. Vista de la Lonja de Mercaderes de Zaragoza (Juan de Sariв”ңв–’ena, 1551), desde la plaza de La Seo. A la izquierda del edificio queda la calle del Pilar; a la derecha, la Casa de la Ciudad (antiguo Ayuntamiento), en la ribera del rв”ңВЎo Ebro; y donde pasa el jinete es la actual calle de Don Jaime I. Fuente: commons.wikimedia.org/wiki/File:Zaragoza_-_La_Lonja.webp', 1858, 1858, 1858, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65566000, -0.87642500, '0101000020E610000096B20C71AC0BECBFCEA5B8AAECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15498200202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15498200202.webp', 'https://www.flickr.com/photos/zaragozaantigua/15498200202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21030, 'Puerta del в”ңГјngel 1860', '"Entrada de SS. MM. en Zaragoza por la puerta del в”ңГјngel el dв”ңВЎa 7 de octubre de 1860". Dibujo con la vista desde el interior de la ciudad de la nueva Puerta del в”ңГјngel, construida en el lugar de la anterior con motivo de la visita de la reina Isabel II, el rey consorte Francisco de Asв”ңВЎs de Borbв”ңв”Ӯn, y los infantes y el heredero al trono, futuro Alfonso XII. A la izquierda, las "casas consistoriales" del viejo ayuntamiento. A la derecha, el edificio del arzobispado en la plaza de la Seo. La puerta estarв”ңГӯ en pie sв”ңв”Ӯlo ocho aв”ңв–’os. Su exagerada ornamentaciв”ңв”Ӯn superior, de materiales efв”ңВЎmeros, todavв”ңВЎa mucho menos. Fuente visual: AMZ', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65590200, -0.87614900, '0101000020E6100000118AADA06909ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24331023153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24331023153.webp', 'https://www.flickr.com/photos/zaragozaantigua/24331023153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21091, 'La Lonja c.1877', 'Imagen capturada en el interior de la nave-salв”ңв”Ӯn de la renacentista Lonja de Mercaderes con una vista transversal orientada hacia el muro oriental y la puerta de ingreso desde la calle de la Lonja. A la izquierda y fuera de plano quedaban las dos puertas que la comunicaban con la anexa Casa Ayuntamiento. Destaca la bв”ңв”Ӯveda de crucerв”ңВЎa estrellada, las columnas denominadas "aragonesas" por la inserciв”ңв”Ӯn de un anillo en su fuste a un tercio de la altura, y la portada ornamentada en relieve y en yeso con el escudo imperial flanqueado por leones. Esta fotografв”ңВЎa resulta excepcional ya que posiblemente incluye en ella el posado del fotв”ңв”Ӯgrafo francв”ңВ®s Jean Laurent, de blanco y sentado a la izquierda, y su equipo de colaboradores.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52453284748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52453284748.webp', 'https://www.flickr.com/photos/zaragozaantigua/52453284748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21113, 'Lonja-Ayuntamiento c.1880', 'Al principio de la antigua calle de la Cuchillerв”ңВЎa, otra imagen de la Lonja en tiempos en que era utilizada como espacio para actos pв”ңв•‘blicos varios, incluyendo el sorteo de "los Quintos" (Servicio Militar Obligatorio para quienes no podв”ңВЎan evadirse pagando), y algunas representaciones teatrales. A su derecha, inmediato, la Casa Consistorial en su ubicaciв”ңв”Ӯn de siglos y siglos, con el edificio levantado unas dв”ңВ®cadas antes, con resabios dieciochescos, y puerta principal de acceso arquitrabado y en orden dв”ңв”Ӯrico. Fuente visual: Anselmo Marв”ңВЎa Coyne, Estudio Coyne (DARA_AHPZ)', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65591300, -0.87633500, '0101000020E610000097E2AAB2EF0AECBFB8020AF5F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23310046131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23310046131.webp', 'https://www.flickr.com/photos/zaragozaantigua/23310046131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21115, 'Calle de la Lonja 1889', 'Fachada principal del renacentista edificio de la Lonja, en una imagen capturada desde la plaza de la Seo. A su izquierda, la calle del Pilar, apenas un callejв”ңв”Ӯn antes del derribo de las parcelas de los nв”ңв•‘meros 36 a 44 accesorio, y la nв”¬в•‘ 7 de la calle de Don Jaime I. A su derecha, las Casas de la ciudad, o ayuntamiento, y el ingreso desde el puente de Piedra. A pesar de que desde mediados del siglo XIX se acometiв”ңв”Ӯ la realineaciв”ңв”Ӯn y la unificaciв”ңв”Ӯn de los varios nombres que, de toda la vida, tenв”ңВЎan los diferentes tramos de la calle Don Jaime I (Nueva de San Gil, Baja de San Pedro, Virgen del Rosario, Cuchillerв”ңВЎa), este todavв”ңВЎa era denominada "calle de la Lonja", y mв”ңГӯs tarde "Fernando el Catв”ңв”Ӯlico". Mientras el seв”ңв–’or Max Junghв”ңГұndel preparaba la cв”ңГӯmara para realizar esta imagen, un heterogв”ңВ®neo grupo de paisanos se ha estacionado en medio, hasta que salga el pajarito. La baja intensidad del trв”ңГӯfico rodado facilitв”ңв”Ӯ un limpio y despejado resultado.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65550100, -0.87642800, '0101000020E6100000DA8EA9BBB20BECBF66BFEE74E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25573691181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25573691181.webp', 'https://www.flickr.com/photos/zaragozaantigua/25573691181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21219, 'Puente de Piedra c.1900', 'Imagen capturada desde cierta altura del puente de Piedra y el Arrabal. Fuente visual: fototipia Lucas Escolв”ңГӯ, en www.memoriademadrid.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65646200, -0.87669800, '0101000020E6100000D6FECEF6E80DECBF8B8862F206D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15672942110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15672942110.webp', 'https://www.flickr.com/photos/zaragozaantigua/15672942110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21232, 'Ribera del Ebro c.1900', 'Imagen capturada desde la ribera del Ebro, junto la "Posada del Rey", espacio de confluencia y descanso de carros, carretas, diligencias, ademв”ңГӯs de las gentes asociadas a estos medios de negocio y transporte. A la izquierda, la verja que delimitaba el palacio de los marqueses de Ayerbe. A la derecha, el puente de Piedra que cruza el Ebro. Al fondo, la iglesia parroquial de Altabв”ңГӯs, el convento de Santa Isabel, y un macizo torreв”ңв”Ӯn del cuartel de San Lв”ңГӯzaro. Fuente visual: Colecciв”ңв”Ӯn Antonio Arguas Perdiguer, en "El libro de oro de Aragв”ңв”Ӯn", EPA, 1997.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65625600, -0.87693200, '0101000020E6100000A01B9AB2D30FECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19376659492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19376659492.webp', 'https://www.flickr.com/photos/zaragozaantigua/19376659492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21287, 'Seв”ңв–’oritas 1903', 'Foto: Algora. "Grupo de las seв”ңв–’oritas que tomaron parte en el concurso de corte organizado por doв”ңв–’a Pilar del Valle y celebrado como final de las fiestas de la patrona de Zaragoza en la Lonja local de dicha poblaciв”ңв”Ӯn". Fuente: Diario ABC, 30-10-1903.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65582800, -0.87663100, '0101000020E6100000E31C75745C0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26075864338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26075864338.webp', 'https://www.flickr.com/photos/zaragozaantigua/26075864338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21360, 'Plaza de La Seo 1900', 'Fotografв”ңВЎa capturada en la plaza de La Seo que continв”ңв•‘a lo representado en la imagen anterior, donde transita el cortejo municipal salido del homв”ңв”Ӯnimo templo durante la celebraciв”ңв”Ӯn, posiblemente, de la festividad del patrв”ңв”Ӯn de la ciudad. Aquв”ңВЎ el cortejo estв”ңГӯ dejando la plaza y cruza la calle de la Lonja, luego de Fernando el Catв”ңв”Ӯlico. Al fondo, fachada de la Casa-Lonja a esta calle. A la derecha e inmediata, esquina del Seminario Conciliar, y hacia el fondo, vista parcial de la Casa Consistorial.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65547900, -0.87635200, '0101000020E61000001A187959130BECBF7E1B62BCE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54788549083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54788549083.webp', 'https://www.flickr.com/photos/zaragozaantigua/54788549083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21372, 'La Lonja y el Pilar 1918', 'Una mirada hacia el Oeste desde la torre de La Seo, capturando la calle Don Jaime I y la del Pilar (con las manzanas de viviendas en su entorno), La Lonja, El Pilar y la arbolada plaza de su nombre. Al fondo, tras la clв”ңВЎnica del Doctor Palomar y el antiguo palacio de Aytona, la torre y cв”ңв•‘pula de San Juan de los Panetes, y el Torreв”ңв”Ӯn de la Zuda. Sobre el Ebro, el puente del Ferrocarril. En la margen izquierda, grandes arboledas, un verdadero bosque de ribera. Fuente: Zaragoza 1908-2008. FCC.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15524839000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15524839000.webp', 'https://www.flickr.com/photos/zaragozaantigua/15524839000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21373, 'La Seo c.1910', 'Fototeca del Patrimonio Artв”ңВЎstico. Archivo Conde de Polentinos. Aurelio de Colmenares y Orgaz. 1892-1930. "Zaragoza II. [Plaza del Pilar y Catedral de San Salvador o la Seo]". Tras voltear horizontalmente la imagen de la Fototeca, muestra correctamente una vista de la plaza de La Seo y la Lonja, desde la calle del Pilar.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65556000, -0.87685800, '0101000020E61000000D8D2782380FECBF6B48DC63E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15608802721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15608802721.webp', 'https://www.flickr.com/photos/zaragozaantigua/15608802721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21451, 'Calle de Don Jaime I c.1918', 'La esquina suroriental de la Lonja marca, a la izquierda, el final de la calle del Pilar en su desemboque en la de don Jaime I, en una imagen realizada desde la inmediata plaza de La Seo, y antes de ser adoquinada esta calle, cuando todavв”ңВЎa mantenв”ңВЎa el tradicional firme de tierra. Desde el puente de Piedra irrumpe por la derecha un tranvв”ңВЎa de la lв”ңВЎnea del Gв”ңГӯllego, posiblemente el nв”¬в•‘ 32, encaminado hacia la terminal en la plaza de la Constituciв”ңв”Ӯn.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65564700, -0.87652400, '0101000020E61000006117450F7C0CECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50784003357.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50784003357.webp', 'https://www.flickr.com/photos/zaragozaantigua/50784003357/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21478, 'La Lonja desde la Seo 1922', 'AHPZ. Archivo Fotogrв”ңГӯfico Julio Requejo. Junio 1922. "La lonja desde la torre de L''Aseo [La Seo]."', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65559100, -0.87643300, '0101000020E61000004C530438BD0BECBFA646E867EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914596106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914596106.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914596106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
